  # ============================================================================
  # Json class for prefix literal support (json{...} syntax)
  # ============================================================================
  let jsonCls = newClass(superclasses = @[objectCls], name = "Json")

  proc primitiveJsonParseLiteralImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.} =
    ## Parse json{...} literal content and return JSON string
    ## Content contains Harding expressions that need to be evaluated
    if args.len < 1 or args[0].kind != vkString:
      return NodeValue(kind: vkString, strVal: "{}")

    let content = args[0].strVal
    if content.len == 0:
      return NodeValue(kind: vkString, strVal: "{}")

    # For now, return the content wrapped as a JSON object string
    # The content was extracted by the parser from between braces
    # TODO: Properly parse and evaluate Harding expressions within the content
    # For API construction, we want to return valid JSON
    var jsonResult = "{"
    var pos = 0
    var first = true

    while pos < content.len:
      # Skip whitespace
      while pos < content.len and content[pos] in {' ', '\t', '\n', '\r'}:
        inc pos

      if pos >= content.len:
        break

      # Expect property name (string or identifier)
      var key = ""
      if content[pos] == '"':
        # Quoted string key
        inc pos
        while pos < content.len and content[pos] != '"':
          if content[pos] == '\\' and pos + 1 < content.len:
            inc pos
          key.add(content[pos])
          inc pos
        if pos < content.len and content[pos] == '"':
          inc pos
      elif content[pos] in {'a'..'z', 'A'..'Z', '_'}:
        # Unquoted identifier key
        while pos < content.len and content[pos] in {'a'..'z', 'A'..'Z', '0'..'9', '_'}:
          key.add(content[pos])
          inc pos
      else:
        break

      # Skip whitespace and expect colon
      while pos < content.len and content[pos] in {' ', '\t', '\n', '\r'}:
        inc pos

      if pos >= content.len or content[pos] != ':':
        break
      inc pos

      # Skip whitespace
      while pos < content.len and content[pos] in {' ', '\t', '\n', '\r'}:
        inc pos

      # Collect value expression (everything until comma or closing brace)
      var valueExpr = ""
      var braceDepth = 0
      var bracketDepth = 0
      var parenDepth = 0
      var inString = false
      var stringChar = '\0'

      while pos < content.len:
        let c = content[pos]

        if inString:
          valueExpr.add(c)
          if c == stringChar:
            inString = false
          elif c == '\\' and pos + 1 < content.len:
            inc pos
            if pos < content.len:
              valueExpr.add(content[pos])
        else:
          case c
          of '"', '\'':
            inString = true
            stringChar = c
            valueExpr.add(c)
          of '{':
            inc braceDepth
            valueExpr.add(c)
          of '}':
            if braceDepth == 0:
              break
            dec braceDepth
            valueExpr.add(c)
          of '[':
            inc bracketDepth
            valueExpr.add(c)
          of ']':
            dec bracketDepth
            valueExpr.add(c)
          of '(':
            inc parenDepth
            valueExpr.add(c)
          of ')':
            dec parenDepth
            valueExpr.add(c)
          of ',':
            if braceDepth == 0 and bracketDepth == 0 and parenDepth == 0:
              break
            valueExpr.add(c)
          else:
            valueExpr.add(c)

        inc pos

      # Use the value expression as-is (it's already been tokenized by the parser)
      # In a full implementation, we would re-parse and evaluate Harding expressions here
      # For now, use the raw value string
      var valueStr = valueExpr.strip()

      # Add to result
      if not first:
        jsonResult.add(", ")
      first = false

      # JSON-escape the key
      var escapedKey = ""
      for c in key:
        case c
        of '"': escapedKey.add("\\\"")
        of '\\': escapedKey.add("\\\\")
        of '\b': escapedKey.add("\\b")
        of '\f': escapedKey.add("\\f")
        of '\n': escapedKey.add("\\n")
        of '\r': escapedKey.add("\\r")
        of '\t': escapedKey.add("\\t")
        else: escapedKey.add(c)
      jsonResult.add("\"" & escapedKey & "\": ")

      # Check if value looks like JSON or needs quoting
      if valueStr.len > 0 and (valueStr[0] == '{' or valueStr[0] == '[' or valueStr == "null" or valueStr == "true" or valueStr == "false" or (valueStr[0] in {'0'..'9', '-'})):
        jsonResult.add(valueStr)
      else:
        # Quote as string
        var escapedValue = ""
        for c in valueStr:
          case c
          of '"': escapedValue.add("\\\"")
          of '\\': escapedValue.add("\\\\")
          of '\b': escapedValue.add("\\b")
          of '\f': escapedValue.add("\\f")
          of '\n': escapedValue.add("\\n")
          of '\r': escapedValue.add("\\r")
          of '\t': escapedValue.add("\\t")
          else: escapedValue.add(c)
        jsonResult.add("\"" & escapedValue & "\"")

      # Skip comma if present
      while pos < content.len and content[pos] in {' ', '\t', '\n', '\r'}:
        inc pos
      if pos < content.len and content[pos] == ',':
        inc pos

    jsonResult.add("}")
    return NodeValue(kind: vkString, strVal: jsonResult)

  proc primitiveJsonParseImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.} =
    ## Parse JSON string into Harding objects
    if args.len < 1 or args[0].kind != vkString:
      return nilValue()

    let jsonStr = args[0].strVal
    try:
      let parsed = parseJson(jsonStr)

      proc jsonToHarding(node: JsonNode): NodeValue =
        case node.kind
        of JObject:
          var entries = initTable[NodeValue, NodeValue]()
          for key, val in node.pairs:
            entries[toValue(key)] = jsonToHarding(val)
          if tableClass != nil:
            return newTableInstance(tableClass, entries).toValue()
          else:
            return NodeValue(kind: vkTable, tableVal: entries)
        of JArray:
          var elements: seq[NodeValue] = @[]
          for elem in node.items:
            elements.add(jsonToHarding(elem))
          if arrayClass != nil:
            return newArrayInstance(arrayClass, elements).toValue()
          else:
            return NodeValue(kind: vkArray, arrayVal: elements)
        of JString:
          return toValue(node.getStr())
        of JInt:
          return NodeValue(kind: vkInt, intVal: node.getInt())
        of JFloat:
          return NodeValue(kind: vkFloat, floatVal: node.getFloat())
        of JBool:
          return NodeValue(kind: vkBool, boolVal: node.getBool())
        of JNull:
          return nilValue()

      return jsonToHarding(parsed)
    except:
      return nilValue()

  proc primitiveJsonStringifyImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.} =
    ## Convert Harding value to JSON string
    if args.len < 1:
      return NodeValue(kind: vkString, strVal: "null")

    let value = args[0]

    proc hardingToJson(val: NodeValue): JsonNode =
      case val.kind
      of vkInt:
        return %val.intVal
      of vkFloat:
        return %val.floatVal
      of vkString:
        return %val.strVal
      of vkBool:
        return %val.boolVal
      of vkNil:
        return newJNull()
      of vkArray:
        var arr = newJArray()
        for elem in val.arrayVal:
          arr.add(hardingToJson(elem))
        return arr
      of vkTable:
        var obj = newJObject()
        for key, val in val.tableVal.pairs:
          obj[key.toString()] = hardingToJson(val)
        return obj
      of vkInstance:
        if val.instVal.kind == ikArray:
          var arr = newJArray()
          for elem in val.instVal.elements:
            arr.add(hardingToJson(elem))
          return arr
        elif val.instVal.kind == ikTable:
          var obj = newJObject()
          for key, entryVal in val.instVal.entries.pairs:
            obj[key.toString()] = hardingToJson(entryVal)
          return obj
        else:
          return %val.toString()
      else:
        return %val.toString()

    return NodeValue(kind: vkString, strVal: $hardingToJson(value))

  let jsonParseLiteralMethod = createCoreMethod("parseLiteral:")
  jsonParseLiteralMethod.setNativeImpl(primitiveJsonParseLiteralImpl)
  setNativeValueFromInstanceWithInterp(jsonParseLiteralMethod, primitiveJsonParseLiteralImpl)
  jsonParseLiteralMethod.hasInterpreterParam = true
  jsonCls.classMethods["parseLiteral:"] = jsonParseLiteralMethod
  jsonCls.allClassMethods["parseLiteral:"] = jsonParseLiteralMethod

  let jsonParseMethod = createCoreMethod("parse:")
  jsonParseMethod.setNativeImpl(primitiveJsonParseImpl)
  setNativeValueFromInstanceWithInterp(jsonParseMethod, primitiveJsonParseImpl)
  jsonParseMethod.hasInterpreterParam = true
  jsonCls.classMethods["parse:"] = jsonParseMethod
  jsonCls.allClassMethods["parse:"] = jsonParseMethod

  let jsonStringifyMethod = createCoreMethod("stringify:")
  jsonStringifyMethod.setNativeImpl(primitiveJsonStringifyImpl)
  setNativeValueFromInstanceWithInterp(jsonStringifyMethod, primitiveJsonStringifyImpl)
  jsonStringifyMethod.hasInterpreterParam = true
  jsonCls.classMethods["stringify:"] = jsonStringifyMethod
  jsonCls.allClassMethods["stringify:"] = jsonStringifyMethod

  jsonClass = jsonCls  # Set global variable

  # Create UndefinedObject class (derives from Object) - the class of nil
  let undefinedObjCls = newClass(superclasses = @[objectCls], name = "UndefinedObject")
  undefinedObjectClass = undefinedObjCls  # Set global variable in types module

  # Create the singleton nil instance (instance of UndefinedObject)
  let nilInst = Instance(kind: ikObject, class: undefinedObjCls, slots: @[])
  nilInstance = nilInst  # Set global variable in types module

  # Note: FileStream class and Stdout instance are created in loadStdlib after
  # loading FileStream.hrd. We avoid creating them here to prevent class
  # identity issues where the .hrd file would replace the Nim-created class.

  # Create Class instance for each class so it can be stored as a value
  # Add global bindings for classes
  interp.globals[]["Root"] = rootCls.toValue()
  interp.globals[]["Object"] = objectCls.toValue()
  interp.globals[]["Number"] = numberCls.toValue()
  interp.globals[]["Integer"] = intCls.toValue()
  interp.globals[]["Float"] = floatCls.toValue()
  interp.globals[]["String"] = stringCls.toValue()
  interp.globals[]["Array"] = arrayCls.toValue()
  interp.globals[]["Table"] = tableCls.toValue()
  interp.globals[]["Set"] = types.setClass.toValue()
  interp.globals[]["Random"] = randomCls.toValue()
  interp.globals[]["Json"] = jsonCls.toValue()
  interp.globals[]["Boolean"] = booleanCls.toValue()
  interp.globals[]["True"] = trueCls.toValue()
  interp.globals[]["False"] = falseCls.toValue()
  interp.globals[]["Block"] = blockCls.toValue()
  interp.globals[]["UndefinedObject"] = undefinedObjCls.toValue()
  interp.globals[]["Library"] = libraryClass.toValue()
  interp.globals[]["Mixin"] = mixinCls.toValue()

  # Create Class class (metaclass) - derives from Object like all classes
  # This allows isKindOf: Class to work properly
  let classCls = newClass(superclasses = @[objectCls], name = "Class")

  # Ensure all class objects (instances of Class) can use core class-side
  # bootstrap constructors like derive/new, not just Object.
  for selector in ["derive", "derive:", "derivePublic:", "derive:read:write:", "derive:read:write:superclasses:", "deriveWithAccessors:", "derive:getters:setters:", "new", "basicNew"]:
    if selector in objectCls.classMethods:
      let meth = objectCls.classMethods[selector]
      classCls.methods[selector] = meth
      classCls.allMethods[selector] = meth

  classClass = classCls  # Set global variable
  interp.globals[]["Class"] = classCls.toValue()

  # Add primitive values
  interp.globals[]["true"] = NodeValue(kind: vkBool, boolVal: true)
  interp.globals[]["false"] = NodeValue(kind: vkBool, boolVal: false)
  interp.globals[]["nil"] = nilValue()

  # Protect core classes and values from reassignment
  protectGlobal("Class")
  protectGlobal("Root")
  protectGlobal("Object")
  protectGlobal("Number")
  protectGlobal("Integer")
  protectGlobal("Float")
  protectGlobal("String")
  protectGlobal("Array")
  protectGlobal("Table")
  protectGlobal("Set")
  protectGlobal("Random")
  protectGlobal("Json")
  protectGlobal("Boolean")
  protectGlobal("True")
  protectGlobal("False")
  protectGlobal("Block")
  protectGlobal("UndefinedObject")
  protectGlobal("true")
  protectGlobal("false")
  protectGlobal("nil")

  # Protect Library global
  protectGlobal("Library")

  # Install Library methods that need interpreter access
  installLibraryMethods()

  # Initialize the Harding global - an instance of GlobalTable that wraps global namespace
  initHardingGlobal(interp)


proc loadStdlib*(interp: var Interpreter, bootstrapFile: string = "") =
  ## Load core library files
  ## If bootstrapFile is provided and exists, it will be loaded and should use
  ## Harding load: to load other files. Otherwise, uses the default Bootstrap.hrd.

  template setNativeValueFromInstance(meth: BlockNode, impl: untyped) =
    meth.setNativeValueImpl(proc(self: NodeValue, args: seq[NodeValue]): NodeValue =
      let receiver = materializeReceiverForSend(self)
      if receiver == nil:
        return nilValue()
      return impl(receiver, args)
    )

  template setNativeValueFromInstanceWithInterp(meth: BlockNode, impl: untyped) =
    meth.setNativeValueImpl(proc(interp: var Interpreter, self: NodeValue, args: seq[NodeValue]): NodeValue =
      let receiver = materializeReceiverForSend(self)
      if receiver == nil:
        return nilValue()
      return impl(interp, receiver, args)
    )
    meth.hasInterpreterParam = true

  # Initialize Process, Scheduler, Monitor, SharedQueue, Semaphore classes
  # Use a callback to avoid circular import with scheduler module
  if interp.schedulerContextPtr != nil:
    # Scheduler is already initialized, classes should be available
    discard

  # Initialize MummyX bridge if compiled with -d:mummyx
  when defined(mummyx):
    initMummyxBridge(interp)
    debug("MummyX bridge initialized")

  # Use lib/core/Bootstrap.hrd as default if no bootstrapFile provided
  let actualBootstrapFile = if bootstrapFile.len > 0 and fileExists(bootstrapFile):
                             bootstrapFile
                           else:
                             interp.hardingHome / "lib" / "core" / "Bootstrap.hrd"

  if fileExists(actualBootstrapFile):
    debug("Loading bootstrap file: ", actualBootstrapFile)
    let source = readFile(actualBootstrapFile)
    let (_, err) = interp.evalStatements(source)
    if err.len > 0:
      stderr.writeLine("WARNING: Failed to load bootstrap file ", actualBootstrapFile, ": ", err)
    else:
      debug("Successfully loaded bootstrap: ", actualBootstrapFile)
  else:
    stderr.writeLine("WARNING: Bootstrap file not found: ", actualBootstrapFile)

  # Set up class caches for primitive types
  if "Number" in interp.globals[]:
    let numVal = interp.globals[]["Number"]
    if numVal.kind == vkClass:
      numberClassCache = numVal.classVal
      debug("Set numberClassCache from Number global")

  if "Integer" in interp.globals[]:
    let intVal = interp.globals[]["Integer"]
    if intVal.kind == vkClass:
      integerClassCache = intVal.classVal
      debug("Set integerClassCache from Integer global")

  if "String" in interp.globals[]:
    let strVal = interp.globals[]["String"]
    if strVal.kind == vkClass:
      stringClassCache = strVal.classVal
      debug("Set stringClassCache from String global")

  if "Symbol" in interp.globals[]:
    let symVal = interp.globals[]["Symbol"]
    if symVal.kind == vkClass:
      symbolClassCache = symVal.classVal
      debug("Set symbolClassCache from Symbol global")

  if "Boolean" in interp.globals[]:
    let boolVal = interp.globals[]["Boolean"]
    if boolVal.kind == vkClass:
      booleanClassCache = boolVal.classVal
      debug("Set booleanClassCache from Boolean global")

  if "True" in interp.globals[]:
    let trueVal = interp.globals[]["True"]
    if trueVal.kind == vkClass:
      trueClassCache = trueVal.classVal
      debug("Set trueClassCache from True global")

  if "False" in interp.globals[]:
    let falseVal = interp.globals[]["False"]
    if falseVal.kind == vkClass:
      falseClassCache = falseVal.classVal
      debug("Set falseClassCache from False global")

  if "Block" in interp.globals[]:
    let blockVal = interp.globals[]["Block"]
    if blockVal.kind == vkClass:
      blockClassCache = blockVal.classVal
      debug("Set blockClassCache from Block global")

  if "Table" in interp.globals[]:
    let tableVal = interp.globals[]["Table"]
    if tableVal.kind == vkClass:
      tableClassCache = tableVal.classVal
      debug("Set tableClassCache from Table global")

  # Set up FileStream class and standard stream globals
  proc findClassInLibraries(interp: Interpreter, name: string): Class =
    for lib in interp.importedLibraries:
      if lib.kind == ikObject and lib.class == libraryClass:
        let bindingsVal = lib.slots[0]
        let lookup = libraryBindingLookup(bindingsVal, name)
        if lookup.found and lookup.value.kind == vkClass:
          return lookup.value.classVal
    return nil

  let fileStreamCls = if "FileStream" in interp.globals[]:
                         let fsVal = interp.globals[]["FileStream"]
                         if fsVal.kind == vkClass: fsVal.classVal else: nil
                       else:
                         findClassInLibraries(interp, "FileStream")

  if fileStreamCls != nil:
    fileStreamCls.isNimProxy = true
    fileStreamCls.hardingType = "FileStream"

    let fsOpenMethod = createCoreMethod("primitiveFileOpen:mode:")
    fsOpenMethod.setNativeImpl(primitiveFileOpenImpl)
    setNativeValueFromInstance(fsOpenMethod, primitiveFileOpenImpl)
    fileStreamCls.methods["primitiveFileOpen:mode:"] = fsOpenMethod
    fileStreamCls.allMethods["primitiveFileOpen:mode:"] = fsOpenMethod

    let fsCloseMethod = createCoreMethod("primitiveFileClose")
    fsCloseMethod.setNativeImpl(primitiveFileCloseImpl)
    setNativeValueFromInstance(fsCloseMethod, primitiveFileCloseImpl)
    fileStreamCls.methods["primitiveFileClose"] = fsCloseMethod
    fileStreamCls.allMethods["primitiveFileClose"] = fsCloseMethod

    let fsReadLineMethod = createCoreMethod("primitiveFileReadLine")
    fsReadLineMethod.setNativeImpl(primitiveFileReadLineImpl)
    setNativeValueFromInstance(fsReadLineMethod, primitiveFileReadLineImpl)
    fileStreamCls.methods["primitiveFileReadLine"] = fsReadLineMethod
    fileStreamCls.allMethods["primitiveFileReadLine"] = fsReadLineMethod

    let fsPrimitiveWriteMethod = createCoreMethod("primitiveFileWrite:")
    fsPrimitiveWriteMethod.setNativeImpl(primitiveFileWriteImpl)
    setNativeValueFromInstance(fsPrimitiveWriteMethod, primitiveFileWriteImpl)
    fileStreamCls.methods["primitiveFileWrite:"] = fsPrimitiveWriteMethod
    fileStreamCls.allMethods["primitiveFileWrite:"] = fsPrimitiveWriteMethod

    let fsAtEndMethod = createCoreMethod("primitiveFileAtEnd")
    fsAtEndMethod.setNativeImpl(primitiveFileAtEndImpl)
    setNativeValueFromInstance(fsAtEndMethod, primitiveFileAtEndImpl)
    fileStreamCls.methods["primitiveFileAtEnd"] = fsAtEndMethod
    fileStreamCls.allMethods["primitiveFileAtEnd"] = fsAtEndMethod

    let fsReadAllMethod = createCoreMethod("primitiveFileReadAll")
    fsReadAllMethod.setNativeImpl(primitiveFileReadAllImpl)
    setNativeValueFromInstance(fsReadAllMethod, primitiveFileReadAllImpl)
    fileStreamCls.methods["primitiveFileReadAll"] = fsReadAllMethod
    fileStreamCls.allMethods["primitiveFileReadAll"] = fsReadAllMethod

    debug("Registered native FileStream primitive methods")

    interp.globals[]["Stdout"] = makeStandardFileStreamInstance(fileStreamCls, fskStdout, "w").toValue()
    interp.globals[]["Stderr"] = makeStandardFileStreamInstance(fileStreamCls, fskStderr, "w").toValue()
    interp.globals[]["Stdin"] = makeStandardFileStreamInstance(fileStreamCls, fskStdin, "r").toValue()
    debug("Created Stdin/Stdout/Stderr instances from FileStream class")

  let systemCls = if "System" in interp.globals[]:
                    let sysVal = interp.globals[]["System"]
                    if sysVal.kind == vkClass: sysVal.classVal else: nil
                  else:
                    findClassInLibraries(interp, "System")

  if systemCls != nil:
    let systemArgsMethod = createCoreMethod("primitiveSystemArguments")
    systemArgsMethod.setNativeImpl(primitiveSystemArgumentsImpl)
    systemArgsMethod.hasInterpreterParam = true
    systemCls.classMethods["primitiveSystemArguments"] = systemArgsMethod
    systemCls.allClassMethods["primitiveSystemArguments"] = systemArgsMethod

    let systemCwdMethod = createCoreMethod("primitiveSystemCwd")
    systemCwdMethod.setNativeImpl(primitiveSystemCwdImpl)
    systemCwdMethod.hasInterpreterParam = true
    systemCls.classMethods["primitiveSystemCwd"] = systemCwdMethod
    systemCls.allClassMethods["primitiveSystemCwd"] = systemCwdMethod

    let systemGetenvMethod = createCoreMethod("primitiveGetenv:")
    systemGetenvMethod.setNativeImpl(primitiveGetenvImpl)
    systemGetenvMethod.hasInterpreterParam = true
    systemCls.classMethods["primitiveGetenv:"] = systemGetenvMethod
    systemCls.allClassMethods["primitiveGetenv:"] = systemGetenvMethod

    debug("Registered native System primitive methods")

  let fileCls = if "File" in interp.globals[]:
                  let fileVal = interp.globals[]["File"]
                  if fileVal.kind == vkClass: fileVal.classVal else: nil
                else:
                  findClassInLibraries(interp, "File")

  if fileCls != nil:
    let fileExistsMethod = createCoreMethod("primitiveFileExists:")
    fileExistsMethod.setNativeImpl(primitiveFileExistsImpl)
    fileExistsMethod.hasInterpreterParam = true
    fileCls.classMethods["primitiveFileExists:"] = fileExistsMethod
    fileCls.allClassMethods["primitiveFileExists:"] = fileExistsMethod

    let fileDeleteMethod = createCoreMethod("primitiveFileDelete:")
    fileDeleteMethod.setNativeImpl(primitiveFileDeleteImpl)
    fileDeleteMethod.hasInterpreterParam = true
    fileCls.classMethods["primitiveFileDelete:"] = fileDeleteMethod
    fileCls.allClassMethods["primitiveFileDelete:"] = fileDeleteMethod
    debug("Registered native File primitive methods")

  # Force rebuild of all method tables after stdlib loading completes
  # This ensures inherited methods are properly populated in allMethods tables
  debug("Forced rebuild of all method tables after stdlib loading")
  if objectClass != nil:
    debug("Object methods before rebuild: ", objectClass.methods.len, " allMethods: ", objectClass.allMethods.len)
    debug("println in Object.methods? ", "println" in objectClass.methods)
    debug("println in Object.allMethods? ", "println" in objectClass.allMethods)
  rebuildAllMethodTables()
  if objectClass != nil:
    debug("Object methods after rebuild: ", objectClass.methods.len, " allMethods: ", objectClass.allMethods.len)
    debug("println in Object.methods? ", "println" in objectClass.methods)
    debug("println in Object.allMethods? ", "println" in objectClass.allMethods)

  when defined(granite):
    # Register Granite compiler primitives
    let graniteCls = if "Granite" in interp.globals[]:
                       let gVal = interp.globals[]["Granite"]
                       if gVal.kind == vkClass: gVal.classVal else: nil
                     else:
                       nil

    if graniteCls != nil:
      # Register primitiveGraniteCompile: primitive (class method)
      # This is called when Granite class>>compile: sourceString <primitive primitiveGraniteCompile: sourceString>
      let primCompileMethod = createCoreMethod("primitiveGraniteCompile:")
      primCompileMethod.setNativeImpl(graniteCompileImpl)
      setNativeValueFromInstance(primCompileMethod, graniteCompileImpl)
      graniteCls.methods["primitiveGraniteCompile:"] = primCompileMethod
      graniteCls.allMethods["primitiveGraniteCompile:"] = primCompileMethod

      # Register primitiveGraniteBuild: primitive (class method)
      # This is called when Granite class>>build: anApplication <primitive primitiveGraniteBuild: anApplication>
      let primBuildMethod = createCoreMethod("primitiveGraniteBuild:")
      primBuildMethod.setNativeImpl(graniteBuildImpl)
      setNativeValueFromInstance(primBuildMethod, graniteBuildImpl)
      graniteCls.methods["primitiveGraniteBuild:"] = primBuildMethod
      graniteCls.allMethods["primitiveGraniteBuild:"] = primBuildMethod

      # Set interpreter reference for primitives
      compiler_primitives.currentInterpreter = interp

      debug("Registered native Granite compiler methods")

  # Register Exception primitive methods
  # First try to find Exception in globals or imported libraries
  var exceptionCls: Class = nil

  debug("Looking for Exception, importedLibraries.len = ", $interp.importedLibraries.len)

  # Check globals first
  if "Exception" in interp.globals[]:
    let exVal = interp.globals[]["Exception"]
    if exVal.kind == vkClass:
      exceptionCls = exVal.classVal
      debug("Found Exception in globals")

  # If not in globals, check imported libraries
  if exceptionCls == nil:
    for lib in interp.importedLibraries:
      debug("Checking imported library, class = ", lib.class.name)
      if lib.kind == ikObject and lib.class != nil and lib.class.name == "Library":
        # Try to get Exception from library bindings
        let bindingsVal = lib.slots[0]  # bindings table is first slot
        debug("Library bindings kind: ", $bindingsVal.kind)
        if bindingsVal.kind == vkInstance and bindingsVal.instVal.kind == ikTable:
          debug("Library has ", $bindingsVal.instVal.entries.len, " entries")
          let exKey = toValue("Exception")
          if exKey in bindingsVal.instVal.entries:
            let exVal = bindingsVal.instVal.entries[exKey]
            debug("Found Exception entry, kind: ", $exVal.kind)
            if exVal.kind == vkClass:
              exceptionCls = exVal.classVal
              debug("Found Exception in imported library")
              break

  if exceptionCls != nil:
    let primitiveSignalMethod = createCoreMethod("primitiveSignal")
    primitiveSignalMethod.setNativeImpl(primitiveSignalImpl)
    setNativeValueFromInstanceWithInterp(primitiveSignalMethod, primitiveSignalImpl)
    primitiveSignalMethod.hasInterpreterParam = true
    exceptionCls.methods["primitiveSignal"] = primitiveSignalMethod
    exceptionCls.allMethods["primitiveSignal"] = primitiveSignalMethod

    # Propagate to all subclasses (since allMethods was already copied)
    proc propagateToSubclasses(cls: Class, methodName: string, meth: BlockNode) =
      for sub in cls.subclasses:
        sub.allMethods[methodName] = meth
        propagateToSubclasses(sub, methodName, meth)
    propagateToSubclasses(exceptionCls, "primitiveSignal", primitiveSignalMethod)

    # Register Exception>>return: primitive
    let returnMethod = createCoreMethod("primitiveExceptionReturn:")
    returnMethod.setNativeImpl(primitiveExceptionReturnImpl)
    setNativeValueFromInstanceWithInterp(returnMethod, primitiveExceptionReturnImpl)
    returnMethod.hasInterpreterParam = true
    exceptionCls.methods["primitiveExceptionReturn:"] = returnMethod
    exceptionCls.allMethods["primitiveExceptionReturn:"] = returnMethod
    propagateToSubclasses(exceptionCls, "primitiveExceptionReturn:", returnMethod)

    # Register Exception>>pass primitive
    let passMethod = createCoreMethod("primitiveExceptionPass")
    passMethod.setNativeImpl(primitiveExceptionPassImpl)
    setNativeValueFromInstanceWithInterp(passMethod, primitiveExceptionPassImpl)
    passMethod.hasInterpreterParam = true
    exceptionCls.methods["primitiveExceptionPass"] = passMethod
    exceptionCls.allMethods["primitiveExceptionPass"] = passMethod
    propagateToSubclasses(exceptionCls, "primitiveExceptionPass", passMethod)

    # Register Exception>>retry primitive
    let retryMethod = createCoreMethod("primitiveExceptionRetry")
    retryMethod.setNativeImpl(primitiveExceptionRetryImpl)
    setNativeValueFromInstanceWithInterp(retryMethod, primitiveExceptionRetryImpl)
    retryMethod.hasInterpreterParam = true
    exceptionCls.methods["primitiveExceptionRetry"] = retryMethod
    exceptionCls.allMethods["primitiveExceptionRetry"] = retryMethod
    propagateToSubclasses(exceptionCls, "primitiveExceptionRetry", retryMethod)

    # Register Exception>>signalContext primitive (for debugging)
    let signalContextMethod = createCoreMethod("primitiveExceptionSignalContext")
    signalContextMethod.setNativeImpl(primitiveExceptionSignalContextImpl)
    setNativeValueFromInstanceWithInterp(signalContextMethod, primitiveExceptionSignalContextImpl)
    signalContextMethod.hasInterpreterParam = true
    exceptionCls.methods["primitiveExceptionSignalContext"] = signalContextMethod
    exceptionCls.allMethods["primitiveExceptionSignalContext"] = signalContextMethod
    propagateToSubclasses(exceptionCls, "primitiveExceptionSignalContext", signalContextMethod)

    # Register Exception>>signaler primitive
    let signalerMethod = createCoreMethod("primitiveExceptionSignaler")
    signalerMethod.setNativeImpl(primitiveExceptionSignalerImpl)
    setNativeValueFromInstanceWithInterp(signalerMethod, primitiveExceptionSignalerImpl)
    signalerMethod.hasInterpreterParam = true
    exceptionCls.methods["primitiveExceptionSignaler"] = signalerMethod
    exceptionCls.allMethods["primitiveExceptionSignaler"] = signalerMethod
    propagateToSubclasses(exceptionCls, "primitiveExceptionSignaler", signalerMethod)

    # Register Exception>>signalActivationDepth primitive
    let signalDepthMethod = createCoreMethod("primitiveExceptionSignalActivationDepth")
    signalDepthMethod.setNativeImpl(primitiveExceptionSignalActivationDepthImpl)
    setNativeValueFromInstanceWithInterp(signalDepthMethod, primitiveExceptionSignalActivationDepthImpl)
    signalDepthMethod.hasInterpreterParam = true
    exceptionCls.methods["primitiveExceptionSignalActivationDepth"] = signalDepthMethod
    exceptionCls.allMethods["primitiveExceptionSignalActivationDepth"] = signalDepthMethod
    propagateToSubclasses(exceptionCls, "primitiveExceptionSignalActivationDepth", signalDepthMethod)

    # Register Exception>>resume primitive
    let resumeMethod = createCoreMethod("primitiveExceptionResume")
    resumeMethod.setNativeImpl(primitiveExceptionResumeImpl)
    setNativeValueFromInstanceWithInterp(resumeMethod, primitiveExceptionResumeImpl)
    resumeMethod.hasInterpreterParam = true
    exceptionCls.methods["primitiveExceptionResume"] = resumeMethod
    exceptionCls.allMethods["primitiveExceptionResume"] = resumeMethod
    propagateToSubclasses(exceptionCls, "primitiveExceptionResume", resumeMethod)

    # Register Exception>>resume: primitive
    let resumeWithMethod = createCoreMethod("primitiveExceptionResume:")
    resumeWithMethod.setNativeImpl(primitiveExceptionResumeWithValueImpl)
    setNativeValueFromInstanceWithInterp(resumeWithMethod, primitiveExceptionResumeWithValueImpl)
    resumeWithMethod.hasInterpreterParam = true
    exceptionCls.methods["primitiveExceptionResume:"] = resumeWithMethod
    exceptionCls.allMethods["primitiveExceptionResume:"] = resumeWithMethod
    propagateToSubclasses(exceptionCls, "primitiveExceptionResume:", resumeWithMethod)

    debug("Registered native Exception>>primitiveSignal method")
  else:
    debug("Exception class not found, cannot register primitiveSignal")

  # Rebuild method tables after direct primitive registrations so all existing
  # classes inherit Object-level reflection/selectors consistently.
  rebuildAllMethodTables()

  # Install external libraries (if any are installed and compiled in)
  when declared(installExternalLibraries):
    installExternalLibraries(interp)

