# Execute code and capture output
proc execWithOutput*(interp: var Interpreter, source: string): (string, string) =
  ## Execute code and capture stdout/stderr separately
  let (value, err) = interp.doit(source)
  if err.len > 0:
    return ("", err)
  else:
    return (value.toString(), "")

# ============================================================================
# FileStream and System primitives
# ============================================================================

proc registerFileStreamProxy(proxy: FileStreamProxy) =
  if proxy != nil and proxy notin fileStreamProxies:
    fileStreamProxies.add(proxy)

proc extractPathArg(val: NodeValue): string =
  case val.kind
  of vkString:
    val.strVal
  of vkSymbol:
    val.symVal
  else:
    ""

proc setNamedSlot(inst: Instance, slotName: string, value: NodeValue) =
  if inst == nil or inst.class == nil:
    return
  let idx = inst.class.allSlotNames.find(slotName)
  if idx >= 0 and idx < inst.slots.len:
    inst.slots[idx] = value

proc getFileStreamProxy(self: Instance): FileStreamProxy =
  if self != nil and self.isNimProxy and self.class != nil and
     self.class.hardingType == "FileStream" and nimValueIsSet(self.nimValue):
    return cast[FileStreamProxy](self.nimValue)
  return nil

proc ensureFileStreamProxy(self: Instance): FileStreamProxy =
  result = getFileStreamProxy(self)
  if result != nil:
    return result
  result = FileStreamProxy(kind: fskClosed)
  registerFileStreamProxy(result)
  self.isNimProxy = true
  self.nimValue = cast[pointer](result)

proc makeStandardFileStreamInstance(fileStreamCls: Class,
                                    kind: FileStreamKind,
                                    mode: string): Instance =
  result = fileStreamCls.newInstance()
  result.isNimProxy = true
  let proxy = FileStreamProxy(kind: kind)
  registerFileStreamProxy(proxy)
  result.nimValue = cast[pointer](proxy)
  setNamedSlot(result, "mode", toValue(mode))
  setNamedSlot(result, "isOpen", toValue(true))

when not defined(js):
  proc parseFileMode(mode: string, fileMode: var FileMode): bool =
    case mode
    of "r":
      fileMode = fmRead
      return true
    of "w":
      fileMode = fmWrite
      return true
    of "a":
      fileMode = fmAppend
      return true
    of "r+":
      fileMode = fmReadWriteExisting
      return true
    of "w+":
      fileMode = fmReadWrite
      return true
    else:
      return false

proc primitiveFileOpenImpl(self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.} =
  if self == nil or args.len < 2:
    return nilValue()

  let filePath = extractPathArg(args[0])
  let mode = extractPathArg(args[1])
  if filePath.len == 0 or mode.len == 0:
    return nilValue()

  when defined(js):
    discard filePath
    discard mode
    writeStderr("Error: FileStream file operations are not available in JS backend")
    return nilValue()
  else:
    var fileMode: FileMode
    if not parseFileMode(mode, fileMode):
      writeStderr("Error: Unsupported file mode: " & mode)
      return nilValue()

    let proxy = ensureFileStreamProxy(self)
    if proxy.kind == fskFile:
      try:
        close(proxy.file)
      except CatchableError:
        discard

    var f: File
    if not open(f, filePath, fileMode):
      setNamedSlot(self, "isOpen", toValue(false))
      writeStderr("Error: Could not open file: " & filePath)
      return nilValue()

    proxy.kind = fskFile
    proxy.file = f
    setNamedSlot(self, "file", toValue(filePath))
    setNamedSlot(self, "mode", toValue(mode))
    setNamedSlot(self, "isOpen", toValue(true))
    return self.toValue()

proc primitiveFileCloseImpl(self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.} =
  discard args
  let proxy = getFileStreamProxy(self)
  if proxy == nil:
    setNamedSlot(self, "isOpen", toValue(false))
    return self.toValue()

  case proxy.kind
  of fskFile:
    when not defined(js):
      try:
        close(proxy.file)
      except CatchableError:
        discard
    proxy.kind = fskClosed
    setNamedSlot(self, "isOpen", toValue(false))
  of fskStdout, fskStderr, fskStdin:
    # Standard streams stay open for the process lifetime.
    discard
  of fskClosed:
    discard
  self.toValue()

proc primitiveFileReadLineImpl(self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.} =
  discard args
  let proxy = getFileStreamProxy(self)
  if proxy == nil:
    return nilValue()

  case proxy.kind
  of fskStdin:
    var line = ""
    if stdin.readLine(line):
      return toValue(line)
    return nilValue()
  of fskFile:
    when defined(js):
      return nilValue()
    else:
      var line = ""
      if proxy.file.readLine(line):
        return toValue(line)
      return nilValue()
  else:
    return nilValue()

proc primitiveFileWriteImpl(self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.} =
  if args.len < 1:
    return self.toValue()

  let text = args[0].toString()
  let proxy = getFileStreamProxy(self)
  if proxy == nil:
    return nilValue()

  case proxy.kind
  of fskStdout:
    stdout.write(text)
    flushFile(stdout)
  of fskStderr:
    stderr.write(text)
    flushFile(stderr)
  of fskFile:
    when defined(js):
      return nilValue()
    else:
      try:
        proxy.file.write(text)
      except CatchableError:
        return nilValue()
  else:
    return nilValue()

  return self.toValue()

proc primitiveFileAtEndImpl(self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.} =
  discard args
  let proxy = getFileStreamProxy(self)
  if proxy == nil:
    return toValue(true)

  case proxy.kind
  of fskFile:
    when defined(js):
      return toValue(true)
    else:
      return toValue(endOfFile(proxy.file))
  of fskStdin:
    return toValue(false)
  of fskStdout, fskStderr:
    return toValue(false)
  of fskClosed:
    return toValue(true)

proc primitiveFileReadAllImpl(self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.} =
  discard args
  let proxy = getFileStreamProxy(self)
  if proxy == nil:
    return nilValue()

  case proxy.kind
  of fskFile:
    when defined(js):
      return nilValue()
    else:
      try:
        return toValue(proxy.file.readAll())
      except CatchableError:
        return nilValue()
  else:
    return nilValue()

proc primitiveFileExistsImpl(interp: var Interpreter,
                             self: Instance,
                             args: seq[NodeValue]): NodeValue {.nimcall.} =
  discard self
  if args.len < 1:
    return toValue(false)

  let requestedPath = extractPathArg(args[0])
  if requestedPath.len == 0:
    return toValue(false)

  let resolvedPath = if requestedPath.isAbsolute:
                       requestedPath
                     else:
                       interp.hardingHome / requestedPath

  if fileExists(resolvedPath):
    return toValue(true)

  if interp.packageSources != nil and
     (requestedPath in interp.packageSources[] or resolvedPath in interp.packageSources[]):
    return toValue(true)

  return toValue(false)

proc primitiveFileDeleteImpl(interp: var Interpreter,
                            self: Instance,
                            args: seq[NodeValue]): NodeValue {.nimcall.} =
  discard self
  if args.len < 1:
    return toValue(false)

  let requestedPath = extractPathArg(args[0])
  if requestedPath.len == 0:
    return toValue(false)

  let resolvedPath = if requestedPath.isAbsolute:
                       requestedPath
                     else:
                       interp.hardingHome / requestedPath

  if fileExists(resolvedPath):
    try:
      removeFile(resolvedPath)
      return toValue(true)
    except CatchableError:
      return toValue(false)

  return toValue(false)

proc primitiveSystemArgumentsImpl(interp: var Interpreter,
                                  self: Instance,
                                  args: seq[NodeValue]): NodeValue {.nimcall.} =
  discard self
  discard args
  var elements: seq[NodeValue] = @[]
  for arg in interp.commandLineArgs:
    elements.add(toValue(arg))
  newArrayInstance(arrayClass, elements).toValue()

proc primitiveSystemCwdImpl(interp: var Interpreter,
                            self: Instance,
                            args: seq[NodeValue]): NodeValue {.nimcall.} =
  discard interp
  discard self
  discard args
  try:
    toValue(getCurrentDir())
  except CatchableError:
    nilValue()

proc primitiveGetenvImpl(interp: var Interpreter,
                         self: Instance,
                         args: seq[NodeValue]): NodeValue {.nimcall.} =
  discard interp
  discard self
  if args.len < 1:
    return nilValue()
  let varName = args[0].toString()
  if varName.len == 0:
    return nilValue()
  let value = getEnv(varName)
  if value.len == 0:
    return nilValue()
  return toValue(value)

proc resolveLoadInput(interp: Interpreter,
                      requestedPath: string): tuple[ok: bool, source: string, displayPath: string] =
  ## Resolve load path from file system or embedded package sources
  if requestedPath.len == 0:
    return (false, "", requestedPath)

  let resolvedPath = if requestedPath.isAbsolute:
                       requestedPath
                     else:
                       interp.hardingHome / requestedPath

  if fileExists(resolvedPath):
    try:
      return (true, readFile(resolvedPath), resolvedPath)
    except CatchableError:
      return (false, "", resolvedPath)

  if not requestedPath.isAbsolute and fileExists(requestedPath):
    try:
      return (true, readFile(requestedPath), requestedPath)
    except CatchableError:
      return (false, "", requestedPath)

  if interp.packageSources != nil:
    if requestedPath in interp.packageSources[]:
      return (true, interp.packageSources[][requestedPath], requestedPath)
    if resolvedPath in interp.packageSources[]:
      return (true, interp.packageSources[][resolvedPath], resolvedPath)

  return (false, "", resolvedPath)

# ============================================================================
# GlobalTable Class and Harding Global
# ============================================================================

type
  GlobalTableProxy* = ref object
    globals*: ref Table[string, NodeValue]

# Keep GlobalTableProxy references alive - stored as raw pointer in nimValue,
# the GC needs to see actual Nim refs to prevent collection
var globalTableProxies: seq[GlobalTableProxy] = @[]

proc createGlobalTableClass*(): Class =
  ## Create the GlobalTable class - a subclass of Table that wraps the globals table
  ## The global globals table is accessible via the 'Harding' global

  # Ensure Table class exists
  if tableClass == nil or objectClass == nil:
    return nil

  if "GlobalTable" in objectClass.allClassMethods or "GlobalTable" in globals:
    # Already initialized
    for name, val in globals:
      if name == "GlobalTable" and val.kind == vkClass:
        return val.classVal

  let globalTableClass = newClass(superclasses = @[tableClass], name = "GlobalTable")
  globalTableClass.isNimProxy = true
  globalTableClass.hardingType = "GlobalTable"

  # GlobalTable inherits all methods from Table (keys, at:, at:put:, includesKey:)
  # No additional methods needed - it just wraps the globals table

  return globalTableClass

proc initHardingGlobal*(interp: var Interpreter) =
  ## Initialize the Harding global - an instance of GlobalTable that wraps global namespace

  # Create the GlobalTable class
  let globalTableClass = createGlobalTableClass()
  if globalTableClass == nil:
    return  # Table class not initialized yet

  # Install special GlobalTable methods that access the globals table
  installGlobalTableMethods(globalTableClass)

  # Create a GlobalTable proxy instance
  let proxy = GlobalTableProxy(globals: interp.globals)
  globalTableProxies.add(proxy)  # Keep reference alive for GC
  let globalTableInstance = Instance(kind: ikObject, class: globalTableClass, slots: @[])
  globalTableInstance.isNimProxy = true
  globalTableInstance.nimValue = cast[pointer](proxy)

  # Add to globals as 'Harding' (the global namespace accessor)
  interp.globals[]["Harding"] = globalTableInstance.toValue()

  # Also add the GlobalTable class itself to globals for reflection
  interp.globals[]["GlobalTable"] = globalTableClass.toValue()

  # Rebuild Object class descendants to ensure subclasses inherit class methods
  # added in this function (initGlobals adds methods directly to objectClass)
  rebuildAllDescendants(objectClass)

# Special handling for GlobalTable - modify Table methods to access globals
proc globalTableAtImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue =
  ## GlobalTable at: - access global variable
  discard self
  let key = if args.len > 0:
              if args[0].kind == vkString: args[0].strVal
              elif args[0].kind == vkSymbol: args[0].symVal
              else: ""
            else:
              ""
  if key.len > 0 and key in interp.globals[]:
    return interp.globals[][key]
  return nilValue()

proc globalTableAtPutImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue =
  ## GlobalTable at:put: - set global variable
  discard self
  if args.len >= 2:
    let key = if args[0].kind == vkString: args[0].strVal
              elif args[0].kind == vkSymbol: args[0].symVal
              else: ""
    if key.len > 0:
      interp.globals[][key] = args[1]
      return args[1]
  return nilValue()

proc globalTableKeysImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue =
  ## GlobalTable keys - get all global names as array
  discard self
  discard args
  var elements: seq[NodeValue] = @[]
  for key in interp.globals[].keys():
    elements.add(toValue(key))
  return NodeValue(kind: vkInstance, instVal: newArrayInstance(arrayClass, elements))

proc globalTableIncludesKeyImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue =
  ## GlobalTable includesKey: - check if global exists
  discard self
  if args.len > 0:
    let key = if args[0].kind == vkString: args[0].strVal
              elif args[0].kind == vkSymbol: args[0].symVal
              else: ""
    return toValue(key in interp.globals[])
  return toValue(false)

proc globalTableLoadImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue =
  ## GlobalTable load: - load and evaluate a Harding file
  ## Resolves paths from filesystem or embedded package sources
  if args.len < 1:
    return nilValue()

  # Get the file path from arguments
  let pathArg = args[0]
  let filePath = case pathArg.kind
    of vkString: pathArg.strVal
    of vkSymbol: pathArg.symVal
    else: ""

  if filePath.len == 0:
    return nilValue()

  let (ok, source, displayPath) = resolveLoadInput(interp, filePath)
  if not ok:
    writeStderr("Error: File not found: " & displayPath)
    return nilValue()

  try:
    # Defer method table rebuilds during batch loading
    interp.methodTableDeferRebuild = true

    let (_, err) = interp.evalStatements(source)
    if err.len > 0:
      writeStderr("Error loading " & displayPath & ": " & err)
      interp.methodTableDeferRebuild = false
      return nilValue()

    # Rebuild all method tables after batch loading
    rebuildAllMethodTables()
    interp.methodTableDeferRebuild = false
    reindexSourceFile(interp, displayPath)

    debug("Successfully loaded: ", displayPath)
    return toValue(true)
  except Exception as e:
    interp.methodTableDeferRebuild = false
    writeStderr("Error reading " & displayPath & ": " & e.msg)
    return nilValue()

proc globalTableCompileImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue =
  ## GlobalTable compile: - evaluate a compile block in interpreter mode
  ## In the interpreter, compile: behaves like a normal block evaluation.
  if args.len < 1:
    return nilValue()

  if args[0].kind == vkBlock and args[0].blockVal != nil:
    return evalBlock(interp, self, args[0].blockVal)

  return nilValue()

proc globalTableMainImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue =
  ## GlobalTable main: - evaluate a main block in interpreter mode
  ## In the interpreter, main: behaves like a normal block evaluation.
  if args.len < 1:
    return nilValue()

  if args[0].kind == vkBlock and args[0].blockVal != nil:
    return evalBlock(interp, self, args[0].blockVal)

  return nilValue()

proc globalTableDumpVMImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue =
  ## Harding dumpVM / dumpVM: - print VM state to stderr.
  discard self
  let label = if args.len > 0: args[0].toString() else: ""
  dumpVmState(interp, label)
  return nilValue()

# ============================================================================
# Library methods (need interpreter access)
# ============================================================================

proc libraryLoadImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue =
  ## Library load: - load and evaluate a file, capturing new globals into this Library's bindings
  if args.len < 1:
    return nilValue()

  let pathArg = args[0]
  let filePath = case pathArg.kind
    of vkString: pathArg.strVal
    of vkSymbol: pathArg.symVal
    else: ""

  if filePath.len == 0:
    return nilValue()

  let (ok, source, displayPath) = resolveLoadInput(interp, filePath)
  if not ok:
    writeStderr("Error: File not found: " & displayPath)
    return nilValue()

  # Save original globals and create a copy for capturing new definitions
  let originalGlobals = interp.globals
  var tempGlobals: ref Table[string, NodeValue]
  new(tempGlobals)
  tempGlobals[] = originalGlobals[]

  # Swap globals to temp table so new definitions go there
  interp.globals = tempGlobals

  try:
    # Defer method table rebuilds during batch loading
    interp.methodTableDeferRebuild = true

    let (_, err) = interp.evalStatements(source)
    if err.len > 0:
      writeStderr("Error loading " & displayPath & ": " & err)
      interp.globals = originalGlobals
      interp.methodTableDeferRebuild = false
      return nilValue()

    # Restore original globals
    interp.globals = originalGlobals

    # Copy new entries into the Library's bindings table
    let bindings = getLibraryBindings(self)
    if bindings != nil:
      for key, val in tempGlobals[]:
        if key notin originalGlobals[]:
          setTableValue(bindings, toValue(key), val)
          debug("Library captured: ", key)

    # Rebuild all method tables after batch loading
    rebuildAllMethodTables()
    interp.methodTableDeferRebuild = false
    reindexSourceFile(interp, displayPath)

    debug("Successfully loaded into library: ", displayPath)
    return toValue(true)
  except Exception as e:
    interp.globals = originalGlobals
    interp.methodTableDeferRebuild = false
    writeStderr("Error reading " & displayPath & ": " & e.msg)
    return nilValue()

proc globalTableImportImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue =
  ## Harding import: - add a Library to the interpreter's imported libraries list
  if args.len < 1:
    return nilValue()

  let libArg = args[0]
  if libArg.kind != vkInstance or libArg.instVal == nil:
    writeStderr("Error: import: argument must be a Library instance")
    return nilValue()

  let lib = libArg.instVal
  if lib.class != libraryClass:
    writeStderr("Error: import: argument must be a Library instance")
    return nilValue()

  interp.importedLibraries.add(lib)
  debug("Imported library, total imports: ", $interp.importedLibraries.len)
  return toValue(true)

proc parseSelectorFromMethodHeader(header: string): string =
  let tokens = header.splitWhitespace()
  if tokens.len == 0:
    return ""

  var keywordSelector = ""
  for tok in tokens:
    if tok.endsWith(":"):
      keywordSelector.add(tok)

  if keywordSelector.len > 0:
    return keywordSelector
  return tokens[0]

proc collectClassNamesForLookup(cls: Class, names: var seq[string]) =
  if cls == nil:
    return
  if cls.name notin names:
    names.add(cls.name)
  for parent in cls.superclasses:
    collectClassNamesForLookup(parent, names)

proc sourceIndexKey(className, selector: string, side: string = "instance"): string =
  className & "|" & side & "|" & selector

proc parseClassDefinitionOwner(line: string): string =
  let assignIdx = line.find(":=")
  if assignIdx < 0:
    return ""
  result = line[0..<assignIdx].strip()

proc clearSourceEntriesForFile(interp: var Interpreter, filePath: string) =
  if interp.sourceFileKeys == nil or interp.sourceIndex == nil:
    return
  if filePath in interp.sourceFileKeys[]:
    for key in interp.sourceFileKeys[][filePath]:
      if key in interp.sourceIndex[]:
        interp.sourceIndex[].del(key)
    interp.sourceFileKeys[].del(filePath)

proc registerSourceEntry(interp: var Interpreter, entry: SourceEntry) =
  if interp.sourceIndex == nil or interp.sourceFileKeys == nil:
    return
  let key = sourceIndexKey(entry.ownerClass, entry.selector, entry.side)
  interp.sourceIndex[][key] = entry
  if entry.filePath notin interp.sourceFileKeys[]:
    interp.sourceFileKeys[][entry.filePath] = @[]
  if key notin interp.sourceFileKeys[][entry.filePath]:
    interp.sourceFileKeys[][entry.filePath].add(key)

proc reindexSourceFile(interp: var Interpreter, filePath: string) =
  if not fileExists(filePath):
    return

  clearSourceEntriesForFile(interp, filePath)

  let lines = readFile(filePath).splitLines()
  var i = 0
  while i < lines.len:
    let rawLine = lines[i]
    let line = rawLine.strip()
    if line.len == 0 or line.startsWith("#"):
      inc(i)
      continue

    let classDefOwner = parseClassDefinitionOwner(line)
    if classDefOwner.len > 0 and line.find(" derive") >= 0:
      var classDefLines: seq[string] = @[line]
      var endLineIdx = i + 1
      while endLineIdx < lines.len:
        let nextRawLine = lines[endLineIdx]
        let nextLine = nextRawLine.strip()
        if nextLine.len == 0:
          break
        if nextLine.startsWith("#"):
          classDefLines.add(nextRawLine)
          inc(endLineIdx)
        else:
          break
      registerSourceEntry(interp, SourceEntry(
        found: true,
        filePath: filePath,
        ownerClass: classDefOwner,
        header: line,
        source: classDefLines.join("\n"),
        suffix: "",
        startLine: i + 1,
        endLine: endLineIdx,
        hasBlock: false,
        selector: "<classDefinition>",
        side: "classdef"
      ))
      i = endLineIdx
      continue

    let sepIdx = line.find(">>")
    if sepIdx < 0:
      inc(i)
      continue

    let headerClass = line[0..<sepIdx].strip()
    var rest = line[(sepIdx + 2)..^1].strip()
    if rest.len == 0:
      inc(i)
      continue

    let primitiveIdx = rest.find("<primitive")
    let bracketIdx = rest.find('[')
    var selectorHeader = rest
    if primitiveIdx >= 0 and (bracketIdx < 0 or primitiveIdx < bracketIdx):
      selectorHeader = rest[0..<primitiveIdx].strip()
    elif bracketIdx >= 0:
      selectorHeader = rest[0..<bracketIdx].strip()

    let parsedSelector = parseSelectorFromMethodHeader(selectorHeader)
    if parsedSelector.len == 0:
      inc(i)
      continue

    var entry = SourceEntry(
      found: true,
      filePath: filePath,
      ownerClass: headerClass,
      header: "",
      source: "",
      suffix: "",
      startLine: i + 1,
      endLine: i + 1,
      hasBlock: false,
      selector: parsedSelector,
      side: if headerClass.endsWith(" class"): "class" else: "instance"
    )

    if primitiveIdx >= 0 and (bracketIdx < 0 or primitiveIdx < bracketIdx):
      entry.header = rawLine.strip()
      var commentLines: seq[string] = @[]
      var endLineIdx = i + 1
      while endLineIdx < lines.len:
        let nextLine = lines[endLineIdx].strip()
        if nextLine.len == 0:
          inc(endLineIdx)
          continue
        if nextLine.startsWith("#"):
          commentLines.add(nextLine)
          inc(endLineIdx)
        else:
          break
      entry.endLine = endLineIdx
      entry.source = if commentLines.len > 0: commentLines.join("\n") else: ""
      registerSourceEntry(interp, entry)
      i = endLineIdx
      continue

    let openIdx = rawLine.find('[')
    if openIdx < 0:
      entry.header = rawLine.strip()
      entry.source = rawLine.strip()
      registerSourceEntry(interp, entry)
      inc(i)
      continue

    entry.hasBlock = true
    entry.header = rawLine[0..<openIdx].strip(trailing = true, leading = false)
    var depth = 1
    var bodyLines: seq[string] = @[]
    var endLineIdx = i
    var suffix = ""
    var currentLine = if openIdx + 1 <= rawLine.high: rawLine[(openIdx + 1)..^1] else: ""
    var closed = false
    while true:
      var extracted = ""
      var j = 0
      while j < currentLine.len:
        let ch = currentLine[j]
        if ch == '[':
          inc(depth)
          extracted.add(ch)
        elif ch == ']':
          if depth == 1:
            dec(depth)
            closed = true
            if j + 1 <= currentLine.high:
              suffix = currentLine[(j + 1)..^1]
            break
          else:
            dec(depth)
            extracted.add(ch)
        else:
          extracted.add(ch)
        inc(j)
      bodyLines.add(extracted)
      if closed:
        break
      inc(endLineIdx)
      if endLineIdx >= lines.len:
        break
      currentLine = lines[endLineIdx]
    entry.endLine = endLineIdx + 1
    entry.source = bodyLines.join("\n").strip(chars = {'\n', '\r'})
    entry.suffix = suffix
    registerSourceEntry(interp, entry)
    i = endLineIdx + 1

proc findIndexedSourceInfo(interp: var Interpreter, className, selector: string): SourceEntry =
  for side in ["instance", "class", "classdef"]:
    let key = sourceIndexKey(className, selector, side)
    if interp.sourceIndex != nil and key in interp.sourceIndex[]:
      let entry = interp.sourceIndex[][key]
      reindexSourceFile(interp, entry.filePath)
      if key in interp.sourceIndex[]:
        return interp.sourceIndex[][key]

proc findMethodInFile(interp: var Interpreter, filePath, className, selector: string): SourceEntry =
  reindexSourceFile(interp, filePath)
  result = findIndexedSourceInfo(interp, className, selector)

proc findMethodSourceInfo(interp: var Interpreter, className, selector: string): SourceEntry =
  result = findIndexedSourceInfo(interp, className, selector)
  if result.found:
    return result

  var classNames: seq[string] = @[className]
  var resolvedClass: Class = nil

  if className in interp.globals[]:
    let classVal = interp.globals[][className]
    if classVal.kind == vkClass and classVal.classVal != nil:
      resolvedClass = classVal.classVal

  if resolvedClass == nil:
    for _, val in interp.globals[].pairs:
      if val.kind == vkClass and val.classVal != nil and val.classVal.name == className:
        resolvedClass = val.classVal
        break

  if resolvedClass != nil:
    classNames = @[]
    collectClassNamesForLookup(resolvedClass, classNames)

  let primaryRoot = joinPath(interp.hardingHome, "lib")
  let libRoot = if dirExists(primaryRoot): primaryRoot else: "lib"

  var files: seq[string] = @[]
  if dirExists(libRoot):
    for path in walkDirRec(libRoot):
      if path.toLowerAscii().endsWith(".hrd"):
        files.add(path)

  for candidateClass in classNames:
    for filePath in files:
      let info = findMethodInFile(interp, filePath, candidateClass, selector)
      if info.found:
        return info

proc sourceEntriesForClass(interp: var Interpreter, className: string): seq[SourceEntry] =
  if interp.sourceIndex == nil:
    return @[]

  var filesSeen: seq[string] = @[]
  for _, entry in interp.sourceIndex[].pairs:
    if entry.ownerClass == className and entry.filePath notin filesSeen:
      filesSeen.add(entry.filePath)

  for filePath in filesSeen:
    reindexSourceFile(interp, filePath)

  for _, entry in interp.sourceIndex[].pairs:
    if entry.ownerClass == className:
      result.add(entry)

  result.sort(proc(a, b: SourceEntry): int =
    if a.startLine < b.startLine: -1
    elif a.startLine > b.startLine: 1
    elif a.selector < b.selector: -1
    elif a.selector > b.selector: 1
    else: 0
  )

proc globalTableMethodSourceInfoImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue =
  ## Harding methodSourceInfoForClass:selector:
  ## Returns a Table with keys: found, file, ownerClass, header, source,
  ## startLine, endLine, hasBlock, suffix
  let infoTable = newTableInstance(tableClass, initTable[NodeValue, NodeValue]())

  if args.len < 2:
    setTableValue(infoTable, toValue("found"), toValue(false))
    return infoTable.toValue()

  let className = case args[0].kind
    of vkString: args[0].strVal
    of vkSymbol: args[0].symVal
    else: ""

  let selector = case args[1].kind
    of vkString: args[1].strVal
    of vkSymbol: args[1].symVal
    else: ""

  if className.len == 0 or selector.len == 0:
    setTableValue(infoTable, toValue("found"), toValue(false))
    return infoTable.toValue()

  let info = findMethodSourceInfo(interp, className, selector)
  setTableValue(infoTable, toValue("found"), toValue(info.found))

  if info.found:
    setTableValue(infoTable, toValue("file"), toValue(info.filePath))
    setTableValue(infoTable, toValue("ownerClass"), toValue(info.ownerClass))
    setTableValue(infoTable, toValue("header"), toValue(info.header))
    setTableValue(infoTable, toValue("source"), toValue(info.source))
    setTableValue(infoTable, toValue("startLine"), toValue(info.startLine))
    setTableValue(infoTable, toValue("endLine"), toValue(info.endLine))
    setTableValue(infoTable, toValue("hasBlock"), toValue(info.hasBlock))
    setTableValue(infoTable, toValue("suffix"), toValue(info.suffix))

  return infoTable.toValue()

proc globalTableSourceEntriesForClassImpl(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue =
  let entriesArray = newArrayInstance(arrayClass, @[])
  if args.len < 1:
    return entriesArray.toValue()

  let className = case args[0].kind
    of vkString: args[0].strVal
    of vkSymbol: args[0].symVal
    else: ""

  if className.len == 0:
    return entriesArray.toValue()

  for entry in sourceEntriesForClass(interp, className):
    let infoTable = newTableInstance(tableClass, initTable[NodeValue, NodeValue]())
    setTableValue(infoTable, toValue("found"), toValue(entry.found))
    setTableValue(infoTable, toValue("file"), toValue(entry.filePath))
    setTableValue(infoTable, toValue("ownerClass"), toValue(entry.ownerClass))
    setTableValue(infoTable, toValue("header"), toValue(entry.header))
    setTableValue(infoTable, toValue("source"), toValue(entry.source))
    setTableValue(infoTable, toValue("startLine"), toValue(entry.startLine))
    setTableValue(infoTable, toValue("endLine"), toValue(entry.endLine))
    setTableValue(infoTable, toValue("hasBlock"), toValue(entry.hasBlock))
    setTableValue(infoTable, toValue("suffix"), toValue(entry.suffix))
    setTableValue(infoTable, toValue("selector"), toValue(entry.selector))
    setTableValue(infoTable, toValue("side"), toValue(entry.side))
    entriesArray.elements.add(infoTable.toValue())

  return entriesArray.toValue()

proc installLibraryMethods*() =
  ## Install Library methods that need interpreter access
  if libraryClass == nil:
    return

  let loadMethod = createCoreMethod("load:")
  loadMethod.setNativeImpl(libraryLoadImpl)
  loadMethod.setNativeValueImpl(proc(interp: var Interpreter, self: NodeValue, args: seq[NodeValue]): NodeValue =
    let receiver = materializeReceiverForSend(self)
    if receiver == nil:
      return nilValue()
    return libraryLoadImpl(interp, receiver, args)
  )
  loadMethod.hasInterpreterParam = true
  addMethodToClass(libraryClass, "load:", loadMethod)

# Patch GlobalTable methods after class creation
proc installGlobalTableMethods*(globalTableClass: Class) =
  ## Install special GlobalTable methods that wrap the globals table
  if globalTableClass == nil:
    return

  # Override at: method
  let atMethod = createCoreMethod("at:")
  atMethod.setNativeImpl(globalTableAtImpl)
  atMethod.setNativeValueImpl(proc(interp: var Interpreter, self: NodeValue, args: seq[NodeValue]): NodeValue =
    let receiver = materializeReceiverForSend(self)
    if receiver == nil:
      return nilValue()
    return globalTableAtImpl(interp, receiver, args)
  )
  atMethod.hasInterpreterParam = true
  addMethodToClass(globalTableClass, "at:", atMethod)

  # Override at:put: method
  let atPutMethod = createCoreMethod("at:put:")
  atPutMethod.setNativeImpl(globalTableAtPutImpl)
  atPutMethod.setNativeValueImpl(proc(interp: var Interpreter, self: NodeValue, args: seq[NodeValue]): NodeValue =
    let receiver = materializeReceiverForSend(self)
    if receiver == nil:
      return nilValue()
    return globalTableAtPutImpl(interp, receiver, args)
  )
  atPutMethod.hasInterpreterParam = true
  addMethodToClass(globalTableClass, "at:put:", atPutMethod)

  # Override keys method
  let keysMethod = createCoreMethod("keys")
  keysMethod.setNativeImpl(globalTableKeysImpl)
  keysMethod.setNativeValueImpl(proc(interp: var Interpreter, self: NodeValue, args: seq[NodeValue]): NodeValue =
    let receiver = materializeReceiverForSend(self)
    if receiver == nil:
      return nilValue()
    return globalTableKeysImpl(interp, receiver, args)
  )
  keysMethod.hasInterpreterParam = true
  addMethodToClass(globalTableClass, "keys", keysMethod)

  # Override includesKey: method
  let includesKeyMethod = createCoreMethod("includesKey:")
  includesKeyMethod.setNativeImpl(globalTableIncludesKeyImpl)
  includesKeyMethod.setNativeValueImpl(proc(interp: var Interpreter, self: NodeValue, args: seq[NodeValue]): NodeValue =
    let receiver = materializeReceiverForSend(self)
    if receiver == nil:
      return nilValue()
    return globalTableIncludesKeyImpl(interp, receiver, args)
  )
  includesKeyMethod.hasInterpreterParam = true
  addMethodToClass(globalTableClass, "includesKey:", includesKeyMethod)

  # Add load: method for loading Harding files
  let loadMethod = createCoreMethod("load:")
  loadMethod.setNativeImpl(globalTableLoadImpl)
  loadMethod.setNativeValueImpl(proc(interp: var Interpreter, self: NodeValue, args: seq[NodeValue]): NodeValue =
    let receiver = materializeReceiverForSend(self)
    if receiver == nil:
      return nilValue()
    return globalTableLoadImpl(interp, receiver, args)
  )
  loadMethod.hasInterpreterParam = true
  addMethodToClass(globalTableClass, "load:", loadMethod)

  # Add import: method for importing Libraries into the interpreter
  let importMethod = createCoreMethod("import:")
  importMethod.setNativeImpl(globalTableImportImpl)
  importMethod.setNativeValueImpl(proc(interp: var Interpreter, self: NodeValue, args: seq[NodeValue]): NodeValue =
    let receiver = materializeReceiverForSend(self)
    if receiver == nil:
      return nilValue()
    return globalTableImportImpl(interp, receiver, args)
  )
  importMethod.hasInterpreterParam = true
  addMethodToClass(globalTableClass, "import:", importMethod)

  # Add compile: and main: methods used by Granite-friendly scripts
  let compileMethod = createCoreMethod("compile:")
  compileMethod.setNativeImpl(globalTableCompileImpl)
  compileMethod.setNativeValueImpl(proc(interp: var Interpreter, self: NodeValue, args: seq[NodeValue]): NodeValue =
    let receiver = materializeReceiverForSend(self)
    if receiver == nil:
      return nilValue()
    return globalTableCompileImpl(interp, receiver, args)
  )
  compileMethod.hasInterpreterParam = true
  addMethodToClass(globalTableClass, "compile:", compileMethod)

  let mainMethod = createCoreMethod("main:")
  mainMethod.setNativeImpl(globalTableMainImpl)
  mainMethod.setNativeValueImpl(proc(interp: var Interpreter, self: NodeValue, args: seq[NodeValue]): NodeValue =
    let receiver = materializeReceiverForSend(self)
    if receiver == nil:
      return nilValue()
    return globalTableMainImpl(interp, receiver, args)
  )
  mainMethod.hasInterpreterParam = true
  addMethodToClass(globalTableClass, "main:", mainMethod)

  let dumpVmMethod = createCoreMethod("dumpVM")
  dumpVmMethod.setNativeImpl(globalTableDumpVMImpl)
  dumpVmMethod.setNativeValueImpl(proc(interp: var Interpreter, self: NodeValue, args: seq[NodeValue]): NodeValue =
    let receiver = materializeReceiverForSend(self)
    if receiver == nil:
      return nilValue()
    return globalTableDumpVMImpl(interp, receiver, args)
  )
  dumpVmMethod.hasInterpreterParam = true
  addMethodToClass(globalTableClass, "dumpVM", dumpVmMethod)

  let dumpVmWithLabelMethod = createCoreMethod("dumpVM:")
  dumpVmWithLabelMethod.setNativeImpl(globalTableDumpVMImpl)
  dumpVmWithLabelMethod.setNativeValueImpl(proc(interp: var Interpreter, self: NodeValue, args: seq[NodeValue]): NodeValue =
    let receiver = materializeReceiverForSend(self)
    if receiver == nil:
      return nilValue()
    return globalTableDumpVMImpl(interp, receiver, args)
  )
  dumpVmWithLabelMethod.hasInterpreterParam = true
  addMethodToClass(globalTableClass, "dumpVM:", dumpVmWithLabelMethod)

  let methodSourceInfoMethod = createCoreMethod("methodSourceInfoForClass:selector:")
  methodSourceInfoMethod.setNativeImpl(globalTableMethodSourceInfoImpl)
  methodSourceInfoMethod.hasInterpreterParam = true
  addMethodToClass(globalTableClass, "methodSourceInfoForClass:selector:", methodSourceInfoMethod)

  let sourceEntriesForClassMethod = createCoreMethod("sourceEntriesForClass:")
  sourceEntriesForClassMethod.setNativeImpl(globalTableSourceEntriesForClassImpl)
  sourceEntriesForClassMethod.hasInterpreterParam = true
  addMethodToClass(globalTableClass, "sourceEntriesForClass:", sourceEntriesForClassMethod)

# ============================================================================
# Explicit Stack AST Interpreter (VM)
# ============================================================================

type
  VMStatus* = enum
    vmRunning     # Normal execution
    vmYielded     # Processor yielded, can be resumed
    vmCompleted   # Execution finished
    vmError       # Error occurred

  VMResult* = object
    status*: VMStatus
    value*: NodeValue
    error*: string

# Work frame constructors
proc newEvalFrame*(node: Node): WorkFrame =
  result = acquireFrame()
  result.kind = wfEvalNode
  result.node = node

proc newSendMessageFrame*(selector: string, argCount: int, msgNode: MessageNode = nil, isClassMethod: bool = false): WorkFrame =
  result = acquireFrame()
  result.kind = wfSendMessage
  result.selector = selector
  result.argCount = argCount
  result.msgNode = msgNode
  result.isClassMethod = isClassMethod

proc newAfterReceiverFrame*(selector: string, args: seq[Node], isClassMethod: bool = false): WorkFrame =
  result = acquireFrame()
  result.kind = wfAfterReceiver
  result.pendingSelector = selector
  result.pendingArgs = args
  result.currentArgIndex = 0
  result.isClassMethod = isClassMethod

proc newAfterArgFrame*(selector: string, args: seq[Node], currentIndex: int, isClassMethod: bool = false): WorkFrame =
  result = acquireFrame()
  result.kind = wfAfterArg
  result.pendingSelector = selector
  result.pendingArgs = args
  result.currentArgIndex = currentIndex
  result.isClassMethod = isClassMethod

proc newApplyBlockFrame*(blockVal: BlockNode, argCount: int): WorkFrame =
  result = acquireFrame()
  result.kind = wfApplyBlock
  result.blockVal = blockVal
  result.argCount = argCount
  result.blockArgs = @[]

proc newReturnValueFrame*(value: NodeValue): WorkFrame =
  result = acquireFrame()
  result.kind = wfReturnValue
  result.returnValue = value

proc newCascadeFrame*(messages: seq[Node], receiver: NodeValue): WorkFrame =
  result = acquireFrame()
  result.kind = wfCascade
  result.cascadeMessages = messages
  result.cascadeReceiver = receiver

proc newPopActivationFrame*(savedReceiver: Instance, isBlock: bool = false, evalStackDepth: int = 0): WorkFrame =
  result = acquireFrame()
  result.kind = wfPopActivation
  result.savedReceiver = savedReceiver
  result.isBlockActivation = isBlock
  result.savedEvalStackDepth = evalStackDepth

proc newIfBranchFrame*(condResult: bool, thenBlock, elseBlock: BlockNode): WorkFrame =
  ## Create a work frame for conditional branch (ifTrue:, ifFalse:)
  result = acquireFrame()
  result.kind = wfIfBranch
  result.conditionResult = condResult
  result.thenBlock = thenBlock
  result.elseBlock = elseBlock

proc newWhileLoopFrame*(loopKind: bool, conditionBlock, bodyBlock: BlockNode, loopState: LoopState): WorkFrame =
  ## Create a work frame for while loop (whileTrue:, whileFalse:)
  result = acquireFrame()
  result.kind = wfWhileLoop
  result.loopKind = loopKind
  result.conditionBlock = conditionBlock
  result.bodyBlock = bodyBlock
  result.loopState = loopState

proc newPushHandlerFrame*(exceptionClass: Class, handlerBlock: BlockNode, savedWorkQueueDepth: int = 0): WorkFrame =
  ## Create a work frame to push an exception handler
  result = acquireFrame()
  result.kind = wfPushHandler
  result.exceptionClass = exceptionClass
  result.handlerBlock = handlerBlock
  result.savedWorkQueueDepth = savedWorkQueueDepth

proc newPopHandlerFrame*(): WorkFrame =
  ## Create a work frame to pop an exception handler
  result = acquireFrame()
  result.kind = wfPopHandler

proc newSignalExceptionFrame*(exceptionInstance: Instance): WorkFrame =
  ## Create a work frame to signal an exception
  result = acquireFrame()
  result.kind = wfSignalException
  result.exceptionInstance = exceptionInstance

proc newExceptionReturnFrame*(handlerIndex: int): WorkFrame =
  ## Create barrier frame for handler completion - unwinds to on:do: point
  result = acquireFrame()
  result.kind = wfExceptionReturn
  result.handlerIndex = handlerIndex

proc newBuildArrayFrame*(count: int): WorkFrame =
  ## Create a work frame for building an array from stack values
  result = acquireFrame()
  result.kind = wfBuildArray
  result.argCount = count

proc newBuildTableFrame*(count: int): WorkFrame =
  ## Create a work frame for building a table from stack key-value pairs
  result = acquireFrame()
  result.kind = wfBuildTable
  result.argCount = count

proc newRestoreReceiverFrame*(savedReceiver: Instance): WorkFrame =
  ## Create a work frame to restore the original receiver after cascade
  result = acquireFrame()
  result.kind = wfRestoreReceiver
  result.savedReceiver = savedReceiver

proc newDiscardFrame*(): WorkFrame =
  ## Create a work frame that discards the result of the previous expression
  result = acquireFrame()
  result.kind = wfAfterArg
  result.pendingSelector = "discard"

proc newAssignFrame*(variable: string, localIndex: int = -1): WorkFrame =
  ## Create a work frame for variable assignment continuation
  result = acquireFrame()
  result.kind = wfAfterArg
  result.pendingSelector = "__assign__"
  result.selector = variable
  result.argCount = localIndex  # Reuse argCount to store local index for fast path
  result.pendingArgs = @[]
  result.currentArgIndex = 0

proc newSlotAssignFrame*(slotIndex: int): WorkFrame =
  ## Create a work frame for slot assignment continuation
  result = acquireFrame()
  result.kind = wfAfterArg
  result.pendingSelector = ":="
  result.currentArgIndex = slotIndex

proc newCascadeMessageFrame*(selector: string, args: seq[Node], receiver: NodeValue): WorkFrame =
  ## Create a work frame for cascade message (keeps result)
  result = acquireFrame()
  result.kind = wfCascadeMessage
  result.pendingSelector = selector
  result.pendingArgs = args
  result.currentArgIndex = 0
  result.cascadeReceiver = receiver

proc newCascadeMessageDiscardFrame*(selector: string, args: seq[Node], receiver: NodeValue): WorkFrame =
  ## Create a work frame for cascade message (discards result)
  result = acquireFrame()
  result.kind = wfCascadeMessageDiscard
  result.pendingSelector = selector
  result.pendingArgs = args
  result.currentArgIndex = 0
  result.cascadeReceiver = receiver

# Stack operations
proc truncateWorkQueue*(interp: var Interpreter, depth: int) =
  ## Truncate work queue to given depth, properly releasing frames to pool
  while interp.workQueue.len > depth:
    let frame = interp.workQueue.pop()
    releaseFrame(frame)

proc pushWorkFrame*(interp: var Interpreter, frame: WorkFrame) =
  interp.workQueue.add(frame)

proc popWorkFrame*(interp: var Interpreter): WorkFrame =
  if interp.workQueue.len == 0:
    raise newException(ValueError, "Work queue underflow")
  result = interp.workQueue.pop()

proc hasWorkFrames*(interp: Interpreter): bool =
  interp.workQueue.len > 0

proc pushValue*(interp: var Interpreter, value: NodeValue) {.inline.} =
  when defined(debug):
    debug("VM: pushValue ", value.toString(), " (stack len will be ", interp.evalStack.len + 1, ")")
  interp.evalStack.add(value)

proc popValue*(interp: var Interpreter): NodeValue {.inline.} =
  if interp.evalStack.len == 0:
    raise newException(ValueError, "Eval stack underflow")
  result = interp.evalStack.pop()
  when defined(debug):
    debug("VM: popValue ", result.toString(), " (stack len now ", interp.evalStack.len, ")")

proc peekValue*(interp: Interpreter): NodeValue {.inline.} =
  if interp.evalStack.len == 0:
    raise newException(ValueError, "Eval stack empty")
  interp.evalStack[^1]

proc popValues*(interp: var Interpreter, count: int): seq[NodeValue] =
  ## Pop multiple values in reverse order (first argument was pushed first)
  result = newSeq[NodeValue](count)
  for i in countdown(count - 1, 0):
    result[i] = interp.popValue()

# Clear VM state
proc clearVMState*(interp: var Interpreter) =
  interp.truncateWorkQueue(0)
  interp.evalStack.setLen(0)

# Handle evaluation of simple nodes (Phase 2)
proc handleEvalNode(interp: var Interpreter, frame: WorkFrame): bool =
  ## Handle wfEvalNode work frame. Returns true if processing should continue.
  let node = frame.node
  if node == nil:
    interp.pushValue(nilValue())
    return true

  case node.kind
  of nkLiteral:
    let lit = cast[LiteralNode](node)
    interp.pushValue(lit.value)
    return true

  of nkIdent:
    let ident = cast[IdentNode](node)
    # Fast path: indexed local access (O(1) instead of hash table lookup)
    # Must check capturedVars first - if a child block captured this variable,
    # the MutableCell may have been updated and indexedLocals would be stale.
    if ident.localIndex >= 0 and interp.currentActivation != nil and
       ident.localIndex < interp.currentActivation.indexedLocals.len:
      if ident.name in interp.currentActivation.capturedVars:
        interp.pushValue(interp.currentActivation.capturedVars[ident.name].value)
      else:
        interp.pushValue(interp.currentActivation.indexedLocals[ident.localIndex])
      return true
    # Slow path: name-based lookup
    let value = lookupVariable(interp, ident.name)
    interp.pushValue(value)
    return true

  of nkPseudoVar:
    let pseudo = cast[PseudoVarNode](node)
    case pseudo.name
    of "self":
      if interp.currentReceiver == nil:
        interp.pushValue(nilValue())
      # For class methods, self should return the Class object
      # We track this via activation.isClassMethod rather than structural checks
      elif interp.currentActivation != nil and interp.currentActivation.isClassMethod:
        interp.pushValue(interp.currentReceiver.class.toValue())
      else:
        # Check if currentReceiver is a class wrapper (instance representing a class).
        # We tag wrappers as isNimProxy with nimValue equal to the class pointer.
        if interp.currentReceiver.kind == ikObject and interp.currentReceiver.class != nil:
          if interp.currentReceiver.isNimProxy and
             interp.currentReceiver.nimValue == cast[pointer](interp.currentReceiver.class):
            # This is a class wrapper - return the class as vkClass
            interp.pushValue(interp.currentReceiver.class.toValue())
          else:
            interp.pushValue(interp.currentReceiver.toValue().unwrap())
        else:
          interp.pushValue(interp.currentReceiver.toValue().unwrap())
    of "nil":
      interp.pushValue(nilValue())
    of "true":
      interp.pushValue(trueValue)
    of "false":
      interp.pushValue(falseValue)
    of "super":
      if interp.currentReceiver != nil:
        interp.pushValue(interp.currentReceiver.toValue().unwrap())
      else:
        interp.pushValue(nilValue())
    else:
      interp.pushValue(nilValue())
    return true

  of nkBlock:
    # Block literal - create a copy and capture environment
    let origBlock = cast[BlockNode](node)
    let blockNode = BlockNode(
      parameters: origBlock.parameters,
      temporaries: origBlock.temporaries,
      body: origBlock.body,
      isMethod: origBlock.isMethod,
      localCount: origBlock.localCount,
      capturedEnv: initTable[string, MutableCell](),
      capturedEnvInitialized: true,
      homeActivation: interp.currentActivation
    )
    captureEnvironment(interp, blockNode)
    interp.pushValue(NodeValue(kind: vkBlock, blockVal: blockNode))
    return true

  of nkAssign:
    # Variable assignment: evaluate expression, then assign
    let assign = cast[AssignNode](node)
    # Push continuation frame to handle assignment after expression is evaluated
    interp.pushWorkFrame(newAssignFrame(assign.variable, assign.localIndex))
    # Evaluate expression
    interp.pushWorkFrame(newEvalFrame(assign.expression))
    return true

  of nkSlotAccess:
    # Slot access - O(1) direct slot access by index
    let slotNode = cast[SlotAccessNode](node)
    if interp.currentReceiver != nil and interp.currentReceiver.kind == ikObject:
      let inst = interp.currentReceiver
      if slotNode.slotIndex >= 0 and slotNode.slotIndex < inst.slots.len:
        if slotNode.isAssignment:
          # Assignment: need to evaluate valueExpr first
          if slotNode.valueExpr != nil:
            # Push continuation to handle slot assignment
            interp.pushWorkFrame(newSlotAssignFrame(slotNode.slotIndex))
            interp.pushWorkFrame(newEvalFrame(slotNode.valueExpr))
            return true
          else:
            interp.pushValue(nilValue())
            return true
        else:
          # Read slot value
          interp.pushValue(inst.slots[slotNode.slotIndex])
          return true
    interp.pushValue(nilValue())
    return true

  of nkNamedAccess:
    return evaluateNamedAccess(interp, cast[NamedAccessNode](node))

  of nkMessage:
    # Message send - will be implemented in Phase 3
    # For now, push placeholder frames
    let msg = cast[MessageNode](node)

    # First evaluate receiver (or use self if nil)
    if msg.receiver != nil:
      interp.pushWorkFrame(newAfterReceiverFrame(msg.selector, msg.arguments))
      interp.pushWorkFrame(newEvalFrame(msg.receiver))
    else:
      # Implicit self as receiver
      if interp.currentReceiver == nil:
        interp.pushValue(nilValue())
      else:
        interp.pushValue(interp.currentReceiver.toValue().unwrap())
      # Now handle arguments
      if msg.arguments.len == 0:
        interp.pushWorkFrame(newSendMessageFrame(msg.selector, 0, msg))
      else:
        interp.pushWorkFrame(newAfterArgFrame(msg.selector, msg.arguments, 0))
        interp.pushWorkFrame(newEvalFrame(msg.arguments[0]))
    return true

  of nkReturn:
    # Return - evaluate expression and push return frame
    let ret = cast[ReturnNode](node)
    if ret.expression != nil:
      # Push placeholder with vkNil (NOT nilValue() which may be vkInstance)
      # This signals to wfReturnValue to pop the value from the stack
      interp.pushWorkFrame(newReturnValueFrame(NodeValue(kind: vkNil)))
      interp.pushWorkFrame(newEvalFrame(ret.expression))
    else:
      # Return self
      if interp.currentReceiver != nil:
        interp.pushWorkFrame(newReturnValueFrame(interp.currentReceiver.toValue().unwrap()))
      else:
        interp.pushWorkFrame(newReturnValueFrame(NodeValue(kind: vkNil)))
    return true

  of nkArray:
    # Array literal - evaluate elements
    let arr = cast[ArrayNode](node)
    # Fast path: use pre-computed constant value
    if arr.isConstant and arr.elements.len > 0:
      if arrayClass != nil:
        interp.pushValue(newArrayInstance(arrayClass, arr.cachedValue.arrayVal).toValue())
      else:
        interp.pushValue(arr.cachedValue)
      return true
    # Standard path: evaluate at runtime
    if arr.elements.len == 0:
      if arrayClass != nil:
        interp.pushValue(newArrayInstance(arrayClass, @[]).toValue())
      else:
        interp.pushValue(NodeValue(kind: vkArray, arrayVal: @[]))
    else:
      # Push build-array frame first (will execute last)
      interp.pushWorkFrame(newBuildArrayFrame(arr.elements.len))
      # Push element evaluation frames in reverse order
      for i in countdown(arr.elements.len - 1, 0):
        let elem = arr.elements[i]
        # Handle special cases for array literals (symbols, keywords)
        if elem.kind == nkIdent:
          let ident = cast[IdentNode](elem)
          case ident.name
          of "true":
            interp.pushWorkFrame(newEvalFrame(PseudoVarNode(name: "true")))
          of "false":
            interp.pushWorkFrame(newEvalFrame(PseudoVarNode(name: "false")))
          of "nil":
            interp.pushWorkFrame(newEvalFrame(PseudoVarNode(name: "nil")))
          else:
            # Bare identifier in array literal is treated as symbol
            interp.pushWorkFrame(newEvalFrame(LiteralNode(value: getSymbol(ident.name))))
        else:
          interp.pushWorkFrame(newEvalFrame(elem))
    return true

  of nkTable:
    # Table literal - evaluate key-value pairs and build table
    let tab = cast[TableNode](node)
    # Fast path: use pre-computed constant value
    if tab.isConstant and tab.entries.len > 0:
      if tableClass != nil:
        interp.pushValue(newTableInstance(tableClass, tab.cachedValue.tableVal).toValue())
      else:
        interp.pushValue(tab.cachedValue)
      return true
    # Standard path: evaluate at runtime
    if tab.entries.len == 0:
      if tableClass != nil:
        interp.pushValue(newTableInstance(tableClass, initTable[NodeValue, NodeValue]()).toValue())
      else:
        interp.pushValue(NodeValue(kind: vkTable, tableVal: initTable[NodeValue, NodeValue]()))
    else:
      # Push build-table frame first (will execute last)
      interp.pushWorkFrame(newBuildTableFrame(tab.entries.len * 2))
      # Push key-value evaluation frames in reverse order (values first, then keys)
      for i in countdown(tab.entries.len - 1, 0):
        let entry = tab.entries[i]
        interp.pushWorkFrame(newEvalFrame(entry.value))  # Value
        interp.pushWorkFrame(newEvalFrame(entry.key))    # Key
    return true

  of nkCascade:
    # Cascade messages - evaluate receiver once, then send each message to same receiver
    let cascade = cast[CascadeNode](node)
    if cascade.messages.len == 0:
      # No messages, just evaluate receiver
      interp.pushWorkFrame(newEvalFrame(cascade.receiver))
    else:
      # Push cascade continuation frame to handle multiple messages
      interp.pushWorkFrame(newCascadeFrame(cascade.messages, nilValue()))
      # Evaluate receiver first
      interp.pushWorkFrame(newEvalFrame(cascade.receiver))
    return true

  of nkSuperSend:
    # Super send - lookup method in parent class
    let superNode = cast[SuperSendNode](node)

    if interp.currentReceiver == nil:
      raise newException(ValueError, "super send with no current receiver")

    # Get the defining class from the current activation
    var definingClass: Class = nil
    if interp.currentActivation != nil and interp.currentActivation.definingObject != nil:
      definingClass = interp.currentActivation.definingObject
    else:
      definingClass = interp.currentReceiver.class

    if definingClass == nil:
      raise newException(ValueError, "super send with no defining class")

    # Determine which parent to look in
    var targetParent: Class = nil
    if superNode.explicitParent.len > 0:
      # Qualified super<Parent>: find specific parent by name
      for parent in definingClass.superclasses:
        if parent.name == superNode.explicitParent:
          targetParent = parent
          break
      if targetParent == nil:
        raise newException(ValueError, "Parent class '" & superNode.explicitParent & "' not found in inheritance chain")
    else:
      # Unqualified super: use first parent of the defining class
      if definingClass.superclasses.len == 0:
        raise newException(ValueError, "super send in class with no parents")
      targetParent = definingClass.superclasses[0]

    # Look up method in target parent's allMethods
    let methodBlock = lookupInstanceMethod(targetParent, superNode.selector)
    if methodBlock == nil:
      raise newException(ValueError, "Method '" & superNode.selector & "' not found in super class " & targetParent.name)

    # Evaluate arguments using evalWithVM, then call executeMethod directly
    # This avoids wfSendMessage which doesn't carry super class context
    var arguments: seq[NodeValue] = @[]
    for argNode in superNode.arguments:
      arguments.add(interp.evalWithVM(argNode))

    let methodResult = executeMethod(interp, methodBlock, interp.currentReceiver, arguments, targetParent)
    interp.pushValue(methodResult)
    return true

  of nkPrimitive:
    # Primitive - evaluate fallback
    let prim = cast[PrimitiveNode](node)
    if prim.fallback.len > 0:
      # Evaluate fallback statements
      for i in countdown(prim.fallback.len - 1, 0):
        if i < prim.fallback.len - 1:
          # Pop intermediate results (only keep last)
          interp.pushWorkFrame(newDiscardFrame())
        interp.pushWorkFrame(newEvalFrame(prim.fallback[i]))
    else:
      interp.pushValue(nilValue())
    return true

  of nkPrimitiveCall:
    # Primitive call - dispatch via standard method lookup on currentReceiver
    let primCall = cast[PrimitiveCallNode](node)
    debug("VM: Primitive call #", primCall.selector, " with ", primCall.arguments.len, " args")
    debug("VM: currentReceiver=", if interp.currentReceiver != nil: interp.currentReceiver.class.name else: "nil")
    debug("VM: isClassMethod=", $primCall.isClassMethod)

    # Push currentReceiver as the receiver
    if interp.currentReceiver != nil:
      interp.pushValue(interp.currentReceiver.toValue().unwrap())
    else:
      interp.pushValue(nilValue())

    # Use the same continuation mechanism as message sends
    if primCall.arguments.len > 0:
      interp.pushWorkFrame(newAfterReceiverFrame(primCall.selector, primCall.arguments, primCall.isClassMethod))
    else:
      interp.pushWorkFrame(newSendMessageFrame(primCall.selector, 0, isClassMethod = primCall.isClassMethod))
    return true

  of nkIf:
    # Control Flow Specialization: IfNode - evaluate condition, then branch
    let ifNode = cast[IfNode](node)
    # Check if condition is a literal boolean (fast path)
    if ifNode.condition of LiteralNode:
      let lit = cast[LiteralNode](ifNode.condition)
      if lit.value.kind == vkBool:
        let condResult = lit.value.boolVal
        if condResult and ifNode.thenBranch != nil:
          let blk = prepareControlFlowBlock(interp, cast[BlockNode](ifNode.thenBranch))
          interp.pushWorkFrame(newApplyBlockFrame(blk, 0))
        elif not condResult and ifNode.elseBranch != nil:
          let blk = prepareControlFlowBlock(interp, cast[BlockNode](ifNode.elseBranch))
          interp.pushWorkFrame(newApplyBlockFrame(blk, 0))
        else:
          interp.pushValue(nilValue())
        return true
    # General case: evaluate condition and create continuation
    # Push continuation frame that will check condition result from stack
    let thenBlk = if ifNode.thenBranch of BlockNode:
        prepareControlFlowBlock(interp, cast[BlockNode](ifNode.thenBranch))
      else: nil
    let elseBlk = if ifNode.elseBranch of BlockNode:
        prepareControlFlowBlock(interp, cast[BlockNode](ifNode.elseBranch))
      else: nil
    var contFrame = WorkFrame(kind: wfIfNodeContinuation)
    contFrame.thenBlock = thenBlk
    contFrame.elseBlock = elseBlk
    interp.pushWorkFrame(contFrame)
    interp.pushWorkFrame(newEvalFrame(ifNode.condition))
    return true

  of nkWhile:
    # Control Flow Specialization: WhileNode - evaluate condition, then body
    let whileNode = cast[WhileNode](node)
    let condBlk = prepareControlFlowBlock(interp, cast[BlockNode](whileNode.condition))
    let bodyBlk = prepareControlFlowBlock(interp, cast[BlockNode](whileNode.body))
    interp.pushWorkFrame(newWhileLoopFrame(whileNode.isWhileTrue, condBlk, bodyBlk, lsEvaluateCondition))
    return true

# Handle continuation frames (what to do after subexpression)
proc handleContinuation(interp: var Interpreter, frame: WorkFrame): bool =
  case frame.kind
  of wfAfterReceiver:
    # Receiver is on stack, now evaluate arguments
    if frame.pendingArgs.len == 0:
      # No arguments - send message now
      interp.pushWorkFrame(newSendMessageFrame(frame.pendingSelector, 0, isClassMethod = frame.isClassMethod))
    else:
      # Evaluate first argument
      interp.pushWorkFrame(newAfterArgFrame(frame.pendingSelector, frame.pendingArgs, 0, frame.isClassMethod))
      interp.pushWorkFrame(newEvalFrame(frame.pendingArgs[0]))
    return true

  of wfAfterArg:
    # Special case: assignment continuation
    if frame.pendingSelector == "__assign__":
      let value = interp.popValue()
      # Fast path: indexed local assignment
      let localIdx = frame.argCount  # localIndex stored in argCount

      var hasCapturedCell = false
      if interp.currentActivation != nil:
        if frame.selector in interp.currentActivation.capturedVars:
          hasCapturedCell = true
        else:
          let currentMethod = interp.currentActivation.currentMethod
          if currentMethod != nil and currentMethod.capturedEnvInitialized and
             currentMethod.capturedEnv.len > 0 and
             frame.selector in currentMethod.capturedEnv:
            hasCapturedCell = true

      if not hasCapturedCell and localIdx >= 0 and interp.currentActivation != nil and
         localIdx < interp.currentActivation.indexedLocals.len:
        interp.currentActivation.indexedLocals[localIdx] = value
        interp.currentActivation.locals[frame.selector] = value
        interp.pushValue(value)
        return true
      # Slow path: name-based assignment
      setVariable(interp, frame.selector, value)
      interp.pushValue(value)
      return true

    # Special case: slot assignment continuation
    if frame.pendingSelector == ":=":
      let value = interp.popValue()
      if interp.currentReceiver != nil and interp.currentReceiver.kind == ikObject:
        let slotIndex = frame.currentArgIndex
        if slotIndex >= 0 and slotIndex < interp.currentReceiver.slots.len:
          interp.currentReceiver.slots[slotIndex] = value
      interp.pushValue(value)
      return true

    # Special case: discard continuation (for primitive fallback)
    if frame.pendingSelector == "discard":
      discard interp.popValue()
      return true

    # Argument evaluated, check if more
    let nextIndex = frame.currentArgIndex + 1
    if nextIndex < frame.pendingArgs.len:
      # More arguments to evaluate
      interp.pushWorkFrame(newAfterArgFrame(frame.pendingSelector, frame.pendingArgs, nextIndex, frame.isClassMethod))
      interp.pushWorkFrame(newEvalFrame(frame.pendingArgs[nextIndex]))
    else:
      # All arguments evaluated - send message
      interp.pushWorkFrame(newSendMessageFrame(frame.pendingSelector, frame.pendingArgs.len, isClassMethod = frame.isClassMethod))
    return true

  of wfSendMessage:
    # Pop args and receiver, send message
    var args: seq[NodeValue]
    var receiverVal: NodeValue
    var singleArg: NodeValue
    var hasSingleArg = false

    case frame.argCount
    of 0:
      receiverVal = interp.popValue()
    of 1:
      hasSingleArg = true
      singleArg = interp.popValue()
      receiverVal = interp.popValue()
    else:
      args = interp.popValues(frame.argCount)
      receiverVal = interp.popValue()

    # Some primitive-compiled sends can come through with a leading '#'
    # in the selector symbol form; normalize to plain selector text.
    if frame.selector.len > 0 and frame.selector[0] == '#':
      frame.selector = frame.selector[1..^1]

    # Handle block invocation
    if receiverVal.kind == vkBlock:
      case frame.selector
      of "value", "value:", "value:value:", "value:value:value:", "value:value:value:value:":
        interp.pushWorkFrame(newApplyBlockFrame(receiverVal.blockVal, frame.argCount))
        # Push args back for block application
        if hasSingleArg:
          interp.pushValue(singleArg)
        else:
          for arg in args:
            interp.pushValue(arg)
        return true
      of "whileTrue:":
        if hasSingleArg and singleArg.kind == vkBlock:
          interp.pushWorkFrame(newWhileLoopFrame(true, receiverVal.blockVal, singleArg.blockVal, lsEvaluateCondition))
          return true
      of "whileFalse:":
        if hasSingleArg and singleArg.kind == vkBlock:
          interp.pushWorkFrame(newWhileLoopFrame(false, receiverVal.blockVal, singleArg.blockVal, lsEvaluateCondition))
          return true
      else:
        discard  # Fall through to regular dispatch

    # ============================================================================
    # FAST PATH: Integer Operations
    # Skip method lookup and receiver materialization for common integer operations
    # ============================================================================
    if receiverVal.kind == vkInt and hasSingleArg and singleArg.kind == vkInt:
      let a = receiverVal.intVal
      let b = singleArg.intVal
      case frame.selector
      of "+":
        interp.pushValue(NodeValue(kind: vkInt, intVal: a + b))
        return true
      of "-":
        interp.pushValue(NodeValue(kind: vkInt, intVal: a - b))
        return true
      of "*":
        interp.pushValue(NodeValue(kind: vkInt, intVal: a * b))
        return true
      of "//":
        if b == 0:
          raise newException(DivByZeroDefect, "Integer division by zero")
        interp.pushValue(NodeValue(kind: vkInt, intVal: a div b))
        return true
      of "%":
        if b == 0:
          raise newException(DivByZeroDefect, "Integer modulo by zero")
        interp.pushValue(NodeValue(kind: vkInt, intVal: a mod b))
        return true
      of "=":
        interp.pushValue(NodeValue(kind: vkBool, boolVal: a == b))
        return true
      of "<":
        interp.pushValue(NodeValue(kind: vkBool, boolVal: a < b))
        return true
      of "<=":
        interp.pushValue(NodeValue(kind: vkBool, boolVal: a <= b))
        return true
      of ">":
        interp.pushValue(NodeValue(kind: vkBool, boolVal: a > b))
        return true
      of ">=":
        interp.pushValue(NodeValue(kind: vkBool, boolVal: a >= b))
        return true
      else:
        discard

    # ============================================================================
    # FAST PATH: Float Operations
    # Skip Instance allocation for primitive float operations
    # ============================================================================
    if receiverVal.kind == vkFloat and hasSingleArg and singleArg.kind == vkFloat:
      let a = receiverVal.floatVal
      let b = singleArg.floatVal

      case frame.selector
      of "+":
        interp.pushValue(NodeValue(kind: vkFloat, floatVal: a + b))
        return true
      of "-":
        interp.pushValue(NodeValue(kind: vkFloat, floatVal: a - b))
        return true
      of "*":
        interp.pushValue(NodeValue(kind: vkFloat, floatVal: a * b))
        return true
      of "/":
        if b == 0.0:
          raise newException(DivByZeroDefect, "Float division by zero")
        interp.pushValue(NodeValue(kind: vkFloat, floatVal: a / b))
        return true
      of "=":
        interp.pushValue(NodeValue(kind: vkBool, boolVal: a == b))
        return true
      of "<":
        interp.pushValue(NodeValue(kind: vkBool, boolVal: a < b))
        return true
      of "<=":
        interp.pushValue(NodeValue(kind: vkBool, boolVal: a <= b))
        return true
      of ">":
        interp.pushValue(NodeValue(kind: vkBool, boolVal: a > b))
        return true
      of ">=":
        interp.pushValue(NodeValue(kind: vkBool, boolVal: a >= b))
        return true
      else:
        discard

    # ============================================================================
    # QUICK PRIMITIVES: Boolean Control Flow
    # Fast-path for ifTrue:, ifFalse:, ifTrue:ifFalse: on tagged booleans
    # Note: nil does NOT respond to ifTrue:/ifFalse: - this should raise DNU
    # ============================================================================
    if receiverVal.kind == vkBool:
      case frame.selector
      of "ifTrue:":
        if hasSingleArg and singleArg.kind == vkBlock:
          if receiverVal.boolVal:
            # true ifTrue: [block] -> evaluate block
            interp.pushWorkFrame(newApplyBlockFrame(singleArg.blockVal, 0))
          else:
            # false ifTrue: [block] -> return nil
            interp.pushValue(nilValue())
          return true
      of "ifFalse:":
        if hasSingleArg and singleArg.kind == vkBlock:
          if not receiverVal.boolVal:
            # false ifFalse: [block] -> evaluate block
            interp.pushWorkFrame(newApplyBlockFrame(singleArg.blockVal, 0))
          else:
            # true ifFalse: [block] -> return nil
            interp.pushValue(nilValue())
          return true
      of "ifTrue:ifFalse:":
        if args.len > 1 and args[0].kind == vkBlock and args[1].kind == vkBlock:
          if receiverVal.boolVal:
            # true ifTrue: [tBlock] ifFalse: [fBlock] -> evaluate tBlock
            interp.pushWorkFrame(newApplyBlockFrame(args[0].blockVal, 0))
          else:
            # false ifTrue: [tBlock] ifFalse: [fBlock] -> evaluate fBlock
            interp.pushWorkFrame(newApplyBlockFrame(args[1].blockVal, 0))
          return true
      of "not":
        if frame.argCount == 0:
          interp.pushValue(NodeValue(kind: vkBool, boolVal: not receiverVal.boolVal))
          return true
      of "and:":
        if hasSingleArg and singleArg.kind == vkBlock:
          # Short-circuit and: evaluate receiver, if false return false, else evaluate block
          if not receiverVal.boolVal:
            interp.pushValue(NodeValue(kind: vkBool, boolVal: false))
          else:
            interp.pushWorkFrame(newApplyBlockFrame(singleArg.blockVal, 0))
          return true
      of "or:":
        if hasSingleArg and singleArg.kind == vkBlock:
          # Short-circuit or: evaluate receiver, if true return true, else evaluate block
          if receiverVal.boolVal:
            interp.pushValue(NodeValue(kind: vkBool, boolVal: true))
          else:
            interp.pushWorkFrame(newApplyBlockFrame(singleArg.blockVal, 0))
          return true
      else:
        discard  # Fall through to normal dispatch for other boolean methods

    # ============================================================================
    # QUICK PRIMITIVES: Common selectors
    # Fast-path for class, isNil, notNil, ==, ~= before MIC/PIC
    # ============================================================================
    case frame.selector
    of ",":
      if hasSingleArg:
        case receiverVal.kind
        of vkString:
          interp.pushValue(NodeValue(kind: vkString, strVal: receiverVal.strVal & singleArg.toString()))
          return true
        of vkSymbol:
          interp.pushValue(NodeValue(kind: vkString, strVal: receiverVal.symVal & singleArg.toString()))
          return true
        else:
          discard

    of "asString":
      if args.len == 0:
        case receiverVal.kind
        of vkString:
          interp.pushValue(receiverVal)
          return true
        of vkSymbol:
          interp.pushValue(NodeValue(kind: vkString, strVal: receiverVal.symVal))
          return true
        of vkInt, vkFloat, vkBool, vkNil:
          interp.pushValue(NodeValue(kind: vkString, strVal: receiverVal.toString()))
          return true
        else:
          discard

    of "printString":
      if args.len == 0:
        case receiverVal.kind
        of vkSymbol:
          interp.pushValue(NodeValue(kind: vkString, strVal: "#" & receiverVal.symVal))
          return true
        of vkInt, vkFloat, vkBool, vkNil:
          interp.pushValue(NodeValue(kind: vkString, strVal: receiverVal.toString()))
          return true
        else:
          discard

    of "size":
      if args.len == 0:
        case receiverVal.kind
        of vkString:
          interp.pushValue(NodeValue(kind: vkInt, intVal: receiverVal.strVal.len))
          return true
        of vkSymbol:
          interp.pushValue(NodeValue(kind: vkInt, intVal: receiverVal.symVal.len))
          return true
        of vkArray:
          interp.pushValue(NodeValue(kind: vkInt, intVal: receiverVal.arrayVal.len))
          return true
        else:
          discard

    of "name":
      if args.len == 0 and receiverVal.kind == vkClass and receiverVal.classVal != nil:
        interp.pushValue(NodeValue(kind: vkString, strVal: receiverVal.classVal.name))
        return true

    of "isClass":
      if args.len == 0 and receiverVal.kind == vkClass:
        interp.pushValue(trueValue)
        return true

    of "isMixin", "primitiveIsMixin":
      if args.len == 0:
        if receiverVal.kind == vkClass and receiverVal.classVal != nil:
          interp.pushValue(toValue(receiverVal.classVal.isMixin))
          return true
        if receiverVal.kind == vkInstance and receiverVal.instVal != nil and
           receiverVal.instVal.kind == ikObject and receiverVal.instVal.class != nil:
          interp.pushValue(toValue(receiverVal.instVal.class.isMixin))
          return true

    of "class":
      if receiverVal.kind == vkClass:
        # For classes, return the class itself (matches original primitiveClassImpl behavior)
        interp.pushValue(receiverVal)
      elif receiverVal.kind == vkBool and trueClassCache != nil and falseClassCache != nil:
        interp.pushValue(NodeValue(kind: vkClass, classVal: if receiverVal.boolVal: trueClassCache else: falseClassCache))
      else:
        let receiverClass = classOfValue(receiverVal)
        if receiverClass != nil:
          interp.pushValue(NodeValue(kind: vkClass, classVal: receiverClass))
        else:
          interp.pushValue(nilValue())
      return true

    of "isNil":
      interp.pushValue(NodeValue(kind: vkBool, boolVal: isNilValue(receiverVal)))
      return true

    of "notNil":
      interp.pushValue(NodeValue(kind: vkBool, boolVal: not isNilValue(receiverVal)))
      return true

    of "==":
      if hasSingleArg:
        interp.pushValue(NodeValue(kind: vkBool, boolVal: identityEqual(receiverVal, singleArg)))
        return true

    of "~=":
      if hasSingleArg:
        interp.pushValue(NodeValue(kind: vkBool, boolVal: not identityEqual(receiverVal, singleArg)))
        return true

    of "=":
      if hasSingleArg and receiverVal.kind != vkInstance and receiverVal.kind != vkBlock and
         singleArg.kind != vkInstance and singleArg.kind != vkBlock:
        interp.pushValue(NodeValue(kind: vkBool, boolVal: receiverVal.unwrap() == singleArg.unwrap()))
        return true

    of "<>":
      if hasSingleArg and receiverVal.kind != vkInstance and receiverVal.kind != vkBlock and
         singleArg.kind != vkInstance and singleArg.kind != vkBlock:
        interp.pushValue(NodeValue(kind: vkBool, boolVal: receiverVal.unwrap() != singleArg.unwrap()))
        return true

    else:
      discard  # Fall through to normal dispatch

    # Convert receiver to Instance for method lookup
    if hasSingleArg:
      args = @[singleArg]

    var receiver: Instance
    debug("VM: Converting receiverVal.kind=", $receiverVal.kind)
    case receiverVal.kind
    of vkInstance:
      receiver = receiverVal.instVal
      debug("VM: vkInstance receiver, class=", if receiver != nil and receiver.class != nil: receiver.class.name else: "NIL")
    of vkClass:
      # Class method lookup
      let cls = receiverVal.classVal
      let lookup = lookupClassMethod(cls, frame.selector)
      if lookup.found:
        let currentMethod = lookup.currentMethod

        if nativeValueImplIsSet(currentMethod):
          interp.pushValue(callNativeValueMethod(interp, currentMethod, receiverVal, args))
          return true

        # Handle native class methods
        if nativeImplIsSet(currentMethod):
          var resultVal: NodeValue
          if currentMethod.hasInterpreterParam:
            let savedReceiver = interp.currentReceiver
            let classReceiver = Instance(kind: ikObject, class: cls, slots: @[], isNimProxy: true,
              nimValue: cast[pointer](cls))
            interp.currentReceiver = classReceiver
            try:
              type NativeProcWithInterp = proc(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.}
              let nativeProc = cast[NativeProcWithInterp](currentMethod.nativeImpl)
              resultVal = nativeProc(interp, classReceiver, args)
            finally:
              interp.currentReceiver = savedReceiver
          else:
            type ClassMethodProc = proc(self: Class, args: seq[NodeValue]): NodeValue {.nimcall.}
            let nativeProc = cast[ClassMethodProc](currentMethod.nativeImpl)
            resultVal = nativeProc(cls, args)
          interp.pushValue(resultVal)
          return true

        # Interpreted class method - create activation with class wrapper as receiver
        let classReceiver = Instance(kind: ikObject, class: cls, slots: @[], isNimProxy: true,
          nimValue: cast[pointer](cls))

        # Check parameter count
        if currentMethod.parameters.len != args.len:
          raise newException(ValueError,
            "Wrong number of arguments: expected " & $currentMethod.parameters.len &
            ", got " & $args.len)

        # Create activation (isClassMethod = true for class methods)
        let activation = newActivation(currentMethod, classReceiver, interp.currentActivation, lookup.definingClass, isClassMethod = true)

        # Bind parameters
        for i in 0..<currentMethod.parameters.len:
          activation.locals[currentMethod.parameters[i]] = args[i]
          activation.bindParam(i, args[i])

        # Initialize temporaries
        for tempName in currentMethod.temporaries:
          if tempName notin activation.locals:
            activation.locals[tempName] = nilValue()

        # Save current receiver
        let savedReceiver = interp.currentReceiver

        # Push activation
        interp.activationStack.add(activation)
        interp.currentActivation = activation
        interp.currentReceiver = classReceiver

        # Set home activation for methods
        if currentMethod.isMethod:
          currentMethod.homeActivation = activation
          activation.wasCaptured = true

        # Push pop-activation frame (save eval stack depth for return unwinding)
        interp.pushWorkFrame(newPopActivationFrame(savedReceiver, isBlock = false, evalStackDepth = interp.evalStack.len))

        # Push method body
        if currentMethod.body.len > 0:
          for i in countdown(currentMethod.body.len - 1, 0):
            if i < currentMethod.body.len - 1:
              interp.pushWorkFrame(newDiscardFrame())
            interp.pushWorkFrame(newEvalFrame(currentMethod.body[i]))
        else:
          interp.pushValue(nilValue())

        return true
      else:
        # Class method not found - try instance methods on the Class class
        # This allows methods like asSelfDo: to work on class receivers
        var instanceLookup = lookupMethodOnClass(interp, classClass, frame.selector)
        if not instanceLookup.found:
          instanceLookup = lookupMethodOnClass(interp, objectClass, frame.selector)

        if instanceLookup.found:
          let currentMethod = instanceLookup.currentMethod
          debug("VM: Found instance method '", frame.selector, "' on Class class")

          if nativeValueImplIsSet(currentMethod):
            interp.pushValue(callNativeValueMethod(interp, currentMethod, receiverVal, args))
            return true

          # Handle native implementations
          if nativeImplIsSet(currentMethod):
            let classReceiver = Instance(kind: ikObject, class: cls, slots: @[], isNimProxy: true,
              nimValue: cast[pointer](cls))
            let savedReceiver = interp.currentReceiver
            interp.currentReceiver = classReceiver
            try:
              var resultVal: NodeValue
              if currentMethod.hasInterpreterParam:
                type NativeProcWithInterp = proc(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.}
                let nativeProc = cast[NativeProcWithInterp](currentMethod.nativeImpl)
                resultVal = nativeProc(interp, classReceiver, args)
              else:
                type NativeProc = proc(self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.}
                let nativeProc = cast[NativeProc](currentMethod.nativeImpl)
                resultVal = nativeProc(classReceiver, args)
              interp.pushValue(resultVal)
            finally:
              interp.currentReceiver = savedReceiver
            return true

          # Interpreted method - create activation
          if currentMethod.parameters.len != args.len:
            raise newException(ValueError,
              "Wrong number of arguments: expected " & $currentMethod.parameters.len &
              ", got " & $args.len)

          let classReceiver = Instance(kind: ikObject, class: cls, slots: @[], isNimProxy: true,
            nimValue: cast[pointer](cls))
          let activation = newActivation(currentMethod, classReceiver, interp.currentActivation, instanceLookup.definingClass)

          for i in 0..<currentMethod.parameters.len:
            activation.locals[currentMethod.parameters[i]] = args[i]
            activation.bindParam(i, args[i])

          for tempName in currentMethod.temporaries:
            if tempName notin activation.locals:
              activation.locals[tempName] = nilValue()

          let savedReceiver = interp.currentReceiver
          interp.activationStack.add(activation)
          interp.currentActivation = activation
          interp.currentReceiver = classReceiver

          if currentMethod.isMethod:
            currentMethod.homeActivation = activation
            activation.wasCaptured = true

          interp.pushWorkFrame(newPopActivationFrame(savedReceiver, isBlock = false, evalStackDepth = interp.evalStack.len))

          if currentMethod.body.len > 0:
            for i in countdown(currentMethod.body.len - 1, 0):
              if i < currentMethod.body.len - 1:
                interp.pushWorkFrame(newDiscardFrame())
              interp.pushWorkFrame(newEvalFrame(currentMethod.body[i]))
          else:
            interp.pushValue(nilValue())

          return true
        else:
          # Instance method not found - try class methods on the class itself and Object
          # This allows class methods like selector:put: to work when called via self in blocks
          # First try the class itself, then try Object's class methods (inherited)
          var classMethodToRun: BlockNode = nil
          var classMethodDefiningClass: Class = nil

          let classMethodLookup = lookupClassMethod(cls, frame.selector)
          if classMethodLookup.found:
            classMethodToRun = classMethodLookup.currentMethod
            classMethodDefiningClass = classMethodLookup.definingClass
          elif objectClass != nil:
            let objectClassMethodLookup = lookupClassMethod(objectClass, frame.selector)
            if objectClassMethodLookup.found:
              classMethodToRun = objectClassMethodLookup.currentMethod
              classMethodDefiningClass = objectClassMethodLookup.definingClass

          if classMethodToRun != nil:
            debug("VM: Found class method '", frame.selector, "' for class ", cls.name)
            if nativeValueImplIsSet(classMethodToRun):
              interp.pushValue(callNativeValueMethod(interp, classMethodToRun, receiverVal, args))
              return true

            # Handle native implementations
            if nativeImplIsSet(classMethodToRun):
              var resultVal: NodeValue
              if classMethodToRun.hasInterpreterParam:
                let classReceiver = Instance(kind: ikObject, class: cls, slots: @[], isNimProxy: true,
                  nimValue: cast[pointer](cls))
                let savedReceiver = interp.currentReceiver
                interp.currentReceiver = classReceiver
                try:
                  type NativeProcWithInterp = proc(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.}
                  let nativeProc = cast[NativeProcWithInterp](classMethodToRun.nativeImpl)
                  resultVal = nativeProc(interp, classReceiver, args)
                finally:
                  interp.currentReceiver = savedReceiver
              else:
                type ClassMethodProc = proc(self: Class, args: seq[NodeValue]): NodeValue {.nimcall.}
                let nativeProc = cast[ClassMethodProc](classMethodToRun.nativeImpl)
                resultVal = nativeProc(cls, args)
              interp.pushValue(resultVal)
              return true

            # Interpreted class method - create activation with class wrapper as receiver
            if classMethodToRun.parameters.len != args.len:
              raise newException(ValueError,
                "Wrong number of arguments: expected " & $classMethodToRun.parameters.len &
                ", got " & $args.len)

            let classReceiver = Instance(kind: ikObject, class: cls, slots: @[], isNimProxy: true,
              nimValue: cast[pointer](cls))
            let activation = newActivation(classMethodToRun, classReceiver, interp.currentActivation, classMethodDefiningClass, isClassMethod = true)

            for i in 0..<classMethodToRun.parameters.len:
              activation.locals[classMethodToRun.parameters[i]] = args[i]
              activation.bindParam(i, args[i])

            for tempName in classMethodToRun.temporaries:
              if tempName notin activation.locals:
                activation.locals[tempName] = nilValue()

            let savedReceiver = interp.currentReceiver
            interp.activationStack.add(activation)
            interp.currentActivation = activation
            interp.currentReceiver = classReceiver

            if classMethodToRun.isMethod:
              classMethodToRun.homeActivation = activation
              activation.wasCaptured = true

            interp.pushWorkFrame(newPopActivationFrame(savedReceiver, isBlock = false, evalStackDepth = interp.evalStack.len))

            if classMethodToRun.body.len > 0:
              for i in countdown(classMethodToRun.body.len - 1, 0):
                if i < classMethodToRun.body.len - 1:
                  interp.pushWorkFrame(newDiscardFrame())
                interp.pushWorkFrame(newEvalFrame(classMethodToRun.body[i]))
            else:
              interp.pushValue(nilValue())

            return true
          else:
            raise newException(ValueError, "Method not found: " & frame.selector)
    of vkBlock:
      # Register BlockNode to keep it alive for ARC
      registerBlockNode(receiverVal.blockVal)
      receiver = Instance(
        kind: ikObject,
        class: blockClass,
        slots: @[],
        isNimProxy: false,
        nimValue: cast[pointer](receiverVal.blockVal)
      )
    else:
      discard

    # Special stackless handling for control flow primitives
    # Native builds only: nimValue pointer operations
    if receiver != nil and receiver.isNimProxy and receiver.kind == ikObject and receiver.class != nil:
        # Boolean ifTrue:/ifFalse: - use stackless work frames
        if (receiver.class == trueClassCache or receiver.class == falseClassCache) and args.len > 0 and args[0].kind == vkBlock:
          case frame.selector
          of "ifTrue:":
            let boolVal = cast[ptr bool](receiver.nimValue)[]
            if boolVal:
              # True - execute then block
              interp.pushWorkFrame(newIfBranchFrame(true, args[0].blockVal, nil))
            else:
              # False - push nil result
              interp.pushValue(nilValue())
            return true
          of "ifFalse:":
            let boolVal = cast[ptr bool](receiver.nimValue)[]
            if not boolVal:
              # False - execute then block (the block passed to ifFalse:)
              interp.pushWorkFrame(newIfBranchFrame(true, args[0].blockVal, nil))
            else:
              # True - push nil result
              interp.pushValue(nilValue())
            return true
          else:
            discard  # Fall through to regular method dispatch

    # Special stackless handling for block whileTrue:/whileFalse:
    if receiver != nil and receiver.kind == ikObject and receiver.class == blockClass and not receiver.isNimProxy and args.len > 0 and args[0].kind == vkBlock:
      let conditionBlock = cast[BlockNode](receiver.nimValue)
      let bodyBlock = args[0].blockVal
      case frame.selector
      of "whileTrue:":
        # Evaluate condition first, then body if true
        interp.pushWorkFrame(newWhileLoopFrame(true, conditionBlock, bodyBlock, lsEvaluateCondition))
        return true
      of "whileFalse:":
        # Evaluate condition first, then body if false
        interp.pushWorkFrame(newWhileLoopFrame(false, conditionBlock, bodyBlock, lsEvaluateCondition))
        return true
      else:
        discard  # Fall through to regular method dispatch

    var receiverClass = classOfValue(receiverVal)
    if receiverVal.kind == vkBool and trueClassCache != nil and falseClassCache != nil:
      receiverClass = if receiverVal.boolVal: trueClassCache else: falseClassCache
    if receiverClass == nil and receiverVal.kind == vkSymbol:
      receiverClass = symbolClassCache
    if receiverClass == nil:
      printStackTrace(interp)
      raise newException(ValueError, "Cannot resolve receiver class for message: " & frame.selector)

    # ============================================================================
    # POLYMORPHIC INLINE CACHE (PIC) CHECK
    # Fast path: check MIC first, then PIC entries
    # ============================================================================
    var currentMethod: BlockNode = nil
    var definingClass: Class = nil
    var cacheHit = false

    if frame.msgNode != nil and not frame.msgNode.megamorphic:
      # Check Monomorphic Inline Cache (MIC) first
      if frame.msgNode.cachedClass != nil and
         receiverClass == frame.msgNode.cachedClass and
         receiverClass.version == frame.msgNode.cachedVersion:
        # MIC hit! Use cached method
        currentMethod = frame.msgNode.cachedMethod
        definingClass = frame.msgNode.cachedClass
        cacheHit = true
        debug("VM: MIC cache hit for '", frame.selector, "' on ", receiverClass.name)
      else:
        # MIC miss - check Polymorphic Inline Cache (PIC)
        for i in 0..<frame.msgNode.picCount:
          if receiverClass == frame.msgNode.picEntries[i].cls and
             receiverClass.version == frame.msgNode.picEntries[i].version:
            # PIC hit - promote to MIC (swap for LRU behavior)
            let oldMIC = (
              cls: frame.msgNode.cachedClass,
              meth: frame.msgNode.cachedMethod,
              version: frame.msgNode.cachedVersion
            )
            currentMethod = frame.msgNode.picEntries[i].meth
            definingClass = frame.msgNode.picEntries[i].cls
            # Promote PIC entry to MIC
            frame.msgNode.cachedClass = frame.msgNode.picEntries[i].cls
            frame.msgNode.cachedMethod = frame.msgNode.picEntries[i].meth
            frame.msgNode.cachedVersion = frame.msgNode.picEntries[i].version
            # Move old MIC to vacated PIC slot
            if oldMIC.cls != nil:
              frame.msgNode.picEntries[i] = oldMIC
            cacheHit = true
            debug("VM: PIC cache hit for '", frame.selector, "' on ", receiverClass.name, " at index ", $i, " (promoted to MIC)")
            break

        if not cacheHit and frame.msgNode.cachedClass != nil:
          # Cache miss - will update cache after lookup
          debug("VM: PIC cache miss for '", frame.selector, "' expected ",
                frame.msgNode.cachedClass.name, " got ", receiverClass.name)

    if not cacheHit:
      # ============================================================================
      # SLOW PATH: Full method lookup
      # ============================================================================
      debug("VM: Looking up method '", frame.selector, "' on ", receiverClass.name, " isClassMethod=", $frame.isClassMethod)

      var lookup: MethodResult
      if frame.isClassMethod:
        # For class method primitives, look in the receiver's class methods
        lookup = lookupClassMethod(receiverClass, frame.selector)
      else:
        lookup = lookupMethodOnClass(interp, receiverClass, frame.selector)

      # Class wrappers are represented as nimProxy instances and can receive
      # Object/Class instance-side reflection methods (e.g. superclassNames).
      # If normal lookup misses on the wrapped class, try Class/Object tables.
      if not lookup.found and receiverVal.kind == vkInstance and receiverVal.instVal != nil and receiverVal.instVal.isNimProxy:
        var classLookup = lookupMethodOnClass(interp, classClass, frame.selector)
        if not classLookup.found:
          classLookup = lookupMethodOnClass(interp, objectClass, frame.selector)
        if classLookup.found:
          lookup = classLookup

      if not lookup.found:
        # Try doesNotUnderstand: before raising error
        debug("VM: Method not found, trying DNU for ", frame.selector)
        let dnuLookup = lookupMethodOnClass(interp, receiverClass, "doesNotUnderstand:")
        debug("VM: DNU lookup result: found=", $dnuLookup.found, " class=", (if dnuLookup.definingClass != nil: dnuLookup.definingClass.name else: "nil"))
        if dnuLookup.found:
          if receiver == nil:
            receiver = materializeReceiverForSend(receiverVal)
          if receiver == nil:
            printStackTrace(interp)
            raise newException(ValueError, "Cannot materialize receiver for DNU: " & frame.selector)
          let selectorVal = NodeValue(kind: vkSymbol, symVal: frame.selector)
          let dnuResult = executeMethod(interp, dnuLookup.currentMethod, receiver, @[selectorVal], dnuLookup.definingClass)
          interp.pushValue(dnuResult)
          return true
        printStackTrace(interp)
        let receiverClassName = if receiverClass != nil: receiverClass.name else: "<nil>"
        raise newException(ValueError, "Message not understood: #" & frame.selector & " (receiver class: " & receiverClassName & ")")

      currentMethod = lookup.currentMethod
      definingClass = lookup.definingClass

      # Update inline cache for future calls (skip for megamorphic sites)
      if frame.msgNode != nil and not frame.msgNode.megamorphic:
        # If MIC already has a different class, move it to PIC (polymorphic cache)
        if frame.msgNode.cachedClass != nil and frame.msgNode.cachedClass != receiverClass:
          if frame.msgNode.picCount < frame.msgNode.picEntries.len:
            # Add old MIC entry to PIC
            frame.msgNode.picEntries[frame.msgNode.picCount] = (
              cls: frame.msgNode.cachedClass,
              meth: frame.msgNode.cachedMethod,
              version: frame.msgNode.cachedVersion
            )
            frame.msgNode.picCount += 1
            debug("VM: Added to PIC for '", frame.selector, "' ", frame.msgNode.cachedClass.name,
                  " (PIC count: ", $frame.msgNode.picCount, ")")
          else:
            # PIC is full - mark as megamorphic, skip all caching
            frame.msgNode.megamorphic = true
            debug("VM: PIC full for '", frame.selector, "', marked megamorphic")

        # Update MIC with new class/method
        if not frame.msgNode.megamorphic:
          frame.msgNode.cachedClass = receiverClass
          frame.msgNode.cachedMethod = currentMethod
          frame.msgNode.cachedVersion = receiverClass.version
          debug("VM: Updated MIC cache for '", frame.selector, "' with ", receiverClass.name)

    # Check for native implementation
    # currentMethod is set either from cache (cacheHit) or from lookup (slow path)
    debug("VM: Found method '", frame.selector, "', native=", nativeImplIsSet(currentMethod), " nativeValue=", nativeValueImplIsSet(currentMethod))
    if nativeValueImplIsSet(currentMethod):
      let savedReceiver = interp.currentReceiver
      try:
        interp.pushValue(callNativeValueMethod(interp, currentMethod, receiverVal, args))
      finally:
        interp.currentReceiver = savedReceiver
      return true

    if receiver == nil:
      receiver = materializeReceiverForSend(receiverVal)
    if receiver == nil:
      printStackTrace(interp)
      raise newException(ValueError, "Cannot materialize receiver for message: " & frame.selector)
    if nativeImplIsSet(currentMethod):
      # Call native method
      debug("VM: receiver ptr=", cast[int](receiver), " receiver class=", if receiver != nil and receiver.class != nil: receiver.class.name else: "NIL")
      let savedReceiver = interp.currentReceiver
      try:
        var resultVal: NodeValue
        if currentMethod.hasInterpreterParam:
          debug("VM: Native method has interpreter param, nativeImpl=", cast[int](currentMethod.nativeImpl))
          type NativeProcWithInterp = proc(interp: var Interpreter, self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.}
          let nativeProc = cast[NativeProcWithInterp](currentMethod.nativeImpl)
          debug("VM: About to call nativeProc, receiver=", (if receiver != nil: receiver.class.name else: "nil"), " receiver ptr=", cast[int](receiver))
          resultVal = nativeProc(interp, receiver, args)
          debug("VM: Native method returned: ", resultVal.toString())
        else:
          type NativeProc = proc(self: Instance, args: seq[NodeValue]): NodeValue {.nimcall.}
          let nativeProc = cast[NativeProc](currentMethod.nativeImpl)
          debug("VM: About to call nativeProc (no interp), receiver=", (if receiver != nil: receiver.class.name else: "nil"), " receiver ptr=", cast[int](receiver))
          resultVal = nativeProc(receiver, args)
        var requeueBlockedSend = false
        if interp.shouldYield and interp.schedulerContextPtr != nil:
          let ctx = cast[SchedulerContext](interp.schedulerContextPtr)
          if ctx != nil and ctx.theScheduler != nil and ctx.theScheduler.currentProcess != nil:
            requeueBlockedSend = ctx.theScheduler.currentProcess.state == psBlocked
        if requeueBlockedSend:
          interp.pushWorkFrame(newSendMessageFrame(frame.selector, frame.argCount, frame.msgNode, frame.isClassMethod))
          interp.pushValue(receiverVal)
          if hasSingleArg:
            interp.pushValue(singleArg)
          else:
            for arg in args:
              interp.pushValue(arg)
          return true
        interp.pushValue(resultVal)
      finally:
        interp.currentReceiver = savedReceiver
      return true

    # Interpreted method - create activation and execute body
    debug("VM: Executing interpreted method '", frame.selector, "' with ", args.len, " args, body has ", currentMethod.body.len, " statements")

    # Check parameter count
    if currentMethod.parameters.len != args.len:
      raise newException(ValueError,
        "Wrong number of arguments: expected " & $currentMethod.parameters.len &
        ", got " & $args.len)

    # Create activation
    let activation = newActivation(currentMethod, receiver, interp.currentActivation, definingClass)

    # Bind parameters
    for i in 0..<currentMethod.parameters.len:
      activation.locals[currentMethod.parameters[i]] = args[i]
      activation.bindParam(i, args[i])

    # Initialize temporaries before any nested block can capture them.
    for tempName in currentMethod.temporaries:
      if tempName notin activation.locals:
        activation.locals[tempName] = nilValue()

    # Save current receiver to restore after method completes
    let savedReceiver = interp.currentReceiver

    # Push activation
    interp.activationStack.add(activation)
    interp.currentActivation = activation
    interp.currentReceiver = receiver

    # Set home activation for methods
    if currentMethod.isMethod:
      currentMethod.homeActivation = activation
      activation.wasCaptured = true

    # Push pop-activation frame FIRST (will execute LAST after body completes)
    interp.pushWorkFrame(newPopActivationFrame(savedReceiver, isBlock = false, evalStackDepth = interp.evalStack.len))

    # Push method body statements in reverse order
    if currentMethod.body.len > 0:
      for i in countdown(currentMethod.body.len - 1, 0):
        if i < currentMethod.body.len - 1:
          # Pop intermediate results (keep only last statement's result)
          interp.pushWorkFrame(newDiscardFrame())
        interp.pushWorkFrame(newEvalFrame(currentMethod.body[i]))
    else:
      # Empty body returns nil
      interp.pushValue(nilValue())

    return true

  of wfApplyBlock:
    # Apply block with args on stack OR from pre-bound blockArgs
    let args = if frame.blockArgs.len > 0:
                 frame.blockArgs  # Use pre-bound args (e.g., from exception handler)
               else:
                 interp.popValues(frame.argCount)  # Pop from eval stack
    let blockNode = frame.blockVal

    # Check argument count
    if blockNode.parameters.len != args.len:
      raise newException(ValueError,
        "Wrong number of arguments to block: expected " & $blockNode.parameters.len &
        ", got " & $args.len)

    # Block's home activation determines 'self'
    # Capture homeActivation NOW before any recursive calls can overwrite blockNode.homeActivation
    let blockHome = blockNode.homeActivation
    let blockReceiver = if blockHome != nil and blockHome.receiver != nil:
                          blockHome.receiver
                        else:
                          interp.currentReceiver

    # Create activation
    let activation = newActivation(blockNode, blockReceiver, interp.currentActivation)

    # Store the home activation at creation time so wfReturnValue uses the correct target
    # even if blockNode.homeActivation is later overwritten by recursive invocations
    activation.blockHomeActivation = blockHome

    # Bind captured environment
    if blockNode.capturedEnvInitialized and blockNode.capturedEnv.len > 0:
      for name, cell in blockNode.capturedEnv:
        activation.locals[name] = cell.value

    # Bind parameters (both indexed and table-based)
    for i in 0..<blockNode.parameters.len:
      activation.locals[blockNode.parameters[i]] = args[i]
      # Also store in indexed locals at index i+1 (0 is self)
      let idx = i + 1
      if idx < activation.indexedLocals.len:
        activation.indexedLocals[idx] = args[i]

    # Initialize temporaries
    for tempName in blockNode.temporaries:
      activation.locals[tempName] = nilValue()

    # Save current receiver to restore after block completes
    let savedReceiver = interp.currentReceiver

    # Push activation
    interp.activationStack.add(activation)
    interp.currentActivation = activation
    interp.currentReceiver = blockReceiver

    # Push pop-activation frame FIRST (will execute LAST after body completes)
    # Store the block in the frame so we can save captured vars back
    var popFrame = newPopActivationFrame(savedReceiver, isBlock = true, evalStackDepth = interp.evalStack.len)
    popFrame.blockVal = blockNode
    interp.pushWorkFrame(popFrame)

    # Push block body statements in reverse order
    if blockNode.body.len > 0:
      for i in countdown(blockNode.body.len - 1, 0):
        if i < blockNode.body.len - 1:
          interp.pushWorkFrame(newDiscardFrame())
        interp.pushWorkFrame(newEvalFrame(blockNode.body[i]))
    else:
      # Empty body returns nil
      interp.pushValue(nilValue())
    return true

  of wfPopActivation:
    # Pop activation after method/block body completes
    # In Smalltalk, methods without explicit ^ return self
    # Blocks return the value of the last expression
    debug("VM: wfPopActivation, evalStack.len=", interp.evalStack.len, " isBlock=", $frame.isBlockActivation, " activationStack.len=", interp.activationStack.len)
    if interp.evalStack.len > 0:
      debug("VM: wfPopActivation top of eval stack: ", interp.evalStack[^1].toString(), " kind=", interp.evalStack[^1].kind)

    # Check for non-local return first.
    # Only treat CURRENT returned block activations as non-local propagation.
    # Method returns are handled in normal completion below.
    var nonLocalReturnActivation: Activation = nil
    if frame.isBlockActivation and
       interp.currentActivation != nil and
       interp.currentActivation.hasReturned:
      nonLocalReturnActivation = interp.currentActivation
    
    if nonLocalReturnActivation != nil:
      # Non-local return - propagate the return value
      debug("VM: wfPopActivation non-local return detected, selector=", (if nonLocalReturnActivation.currentMethod != nil: nonLocalReturnActivation.currentMethod.selector else: "nil"))
      let returnVal = nonLocalReturnActivation.returnValue

      # Pop the activation
      discard interp.activationStack.pop()
      if interp.activationStack.len > 0:
        interp.currentActivation = interp.activationStack[^1]
        interp.currentReceiver = interp.currentActivation.receiver
      else:
        interp.currentActivation = nil
        interp.currentReceiver = frame.savedReceiver

      interp.pushValue(returnVal.unwrap())
    else:
      # Normal completion - get return value BEFORE popping activation
      var resultValue: NodeValue
      if frame.isBlockActivation:
        # Blocks return the value of the last expression
        if interp.evalStack.len > 0:
          resultValue = interp.popValue()
        else:
          resultValue = nilValue()
        debug("VM: wfPopActivation block result: ", resultValue.toString())
      else:
        # Methods without explicit ^ return self
        if interp.currentActivation != nil and interp.currentActivation.hasReturned:
          if interp.evalStack.len > frame.savedEvalStackDepth:
            interp.evalStack.setLen(frame.savedEvalStackDepth)
          resultValue = interp.currentActivation.returnValue
          debug("VM: wfPopActivation method result: explicit return value")
        else:
          # Pop any leftover values from the stack (expressions that were evaluated)
          if interp.evalStack.len > frame.savedEvalStackDepth:
            discard interp.popValue()
          # Return self (the receiver of the method being popped)
          # Must get this BEFORE popping the activation
          if interp.currentActivation != nil and interp.currentActivation.receiver != nil:
            resultValue = interp.currentActivation.receiver.toValue().unwrap()
          else:
            resultValue = nilValue()
          debug("VM: wfPopActivation method result: self")

      # Now pop the activation
      debug("VM: wfPopActivation popping activation, len before=", interp.activationStack.len)
      let poppedAct = interp.activationStack.pop()
      releaseActivation(poppedAct)
      debug("VM: wfPopActivation popping activation, len after=", interp.activationStack.len)
      if interp.activationStack.len > 0:
        interp.currentActivation = interp.activationStack[^1]
        interp.currentReceiver = interp.currentActivation.receiver
        debug("VM: wfPopActivation new currentActivation receiver set")
      else:
        interp.currentActivation = nil
        interp.currentReceiver = frame.savedReceiver
        debug("VM: wfPopActivation no more activations, restored savedReceiver")


      interp.pushValue(resultValue.unwrap())

    return true

  of wfReturnValue:
    # Handle return (^ expression) - must unwind work queue to target activation
    let value = if frame.returnValue.kind != vkNil:
                  frame.returnValue
                else:
                  interp.popValue()
    let returnVal = value.unwrap()
    # Find target activation for the return
    # For blocks, target is homeActivation (the enclosing method)
    # For methods, target is the current activation
    var targetActivation: Activation = nil
    var isNonLocalReturn = false  # Track if this is a non-local return from a block
    if interp.currentActivation != nil and interp.currentActivation.currentMethod != nil:
      let currentMethod = interp.currentActivation.currentMethod
      # Use blockHomeActivation (captured at creation time) if available, to avoid
      # using a stale/overwritten blockNode.homeActivation from recursive invocations
      let effectiveHomeActivation = if interp.currentActivation.blockHomeActivation != nil:
                                       interp.currentActivation.blockHomeActivation
                                     else:
                                       currentMethod.homeActivation
      if not currentMethod.isMethod and effectiveHomeActivation != nil:
        # This is a non-local return from a block - walk up to find the method activation
        isNonLocalReturn = true
        var homeAct = effectiveHomeActivation
        while homeAct != nil and homeAct.currentMethod != nil and not homeAct.currentMethod.isMethod:
          let nextHome = if homeAct.blockHomeActivation != nil: homeAct.blockHomeActivation
                         else: homeAct.currentMethod.homeActivation
          homeAct = nextHome
        targetActivation = if homeAct != nil: homeAct else: effectiveHomeActivation
      else:
        # Normal return from a method - target is the current method itself
        targetActivation = interp.currentActivation

    debug("wfReturnValue: current selector=",
      if interp.currentActivation != nil and interp.currentActivation.currentMethod != nil:
        interp.currentActivation.currentMethod.selector
      else:
        "nil",
      " target selector=",
      if targetActivation != nil and targetActivation.currentMethod != nil:
        targetActivation.currentMethod.selector
      else:
        "nil",
      " isNonLocal=", $isNonLocalReturn)

    if targetActivation == nil:
      # No target - just push value (shouldn't happen in well-formed code)
      debug("VM: wfReturnValue no target activation!")
      interp.pushValue(returnVal)
      return true

    # Fast path for ordinary local method returns (legacy executeMethod path).
    # Do not unwind workQueue here, because queued frames may belong to caller
    # expressions (e.g. outer binary sends like `C count < 5`).
    if not isNonLocalReturn and targetActivation == interp.currentActivation:
      targetActivation.hasReturned = true
      targetActivation.returnValue = returnVal
      return true

    # Check if target activation is still on the stack (handles escaped blocks
    # where the home method has already returned)
    var targetOnStack = false
    for i in 0..<interp.activationStack.len:
      if interp.activationStack[i] == targetActivation:
        targetOnStack = true
        break

    if not targetOnStack:
      # Target method already returned (escaped block with non-local return).
      # Treat as local return: set hasReturned on current activation so
      # wfPopActivation will propagate the value up correctly.
      if interp.currentActivation != nil:
        interp.currentActivation.hasReturned = true
        interp.currentActivation.returnValue = returnVal
      interp.pushValue(returnVal)
      return true

    # Unwind: pop work frames and activations until we find the target
    # For non-local returns, we need to unwind both the work queue AND the activation stack
    debug("wfReturnValue: targetActivation nil?=", $(targetActivation == nil), " targetOnStack=", $targetOnStack)
    var found = false
    var targetEvalStackDepth = 0
    var preservedTargetCleanup = false
    
    # First, unwind the work queue
    while interp.workQueue.len > 0 and not found:
      let wf = interp.workQueue.pop()
      # Skip continuation frames from control flow specialization
      if wf.kind == wfIfNodeContinuation:
        # Pop the condition result that would have been consumed
        if interp.evalStack.len > 0:
          discard interp.evalStack.pop()
        continue
      if wf.kind == wfWhileLoop:
        # Pop the condition result if we're in the check state
        if wf.loopState == lsCheckCondition and interp.evalStack.len > 0:
          discard interp.evalStack.pop()
        continue
      if wf.kind == wfPopActivation:
        # Check if the current activation is the target
        debug("wfReturnValue: checking wfPopActivation, currentActivation==targetActivation? ", $(interp.currentActivation == targetActivation))
        
        # First, check if top of activation stack is the target
        if interp.activationStack.len > 0 and interp.activationStack[^1] == targetActivation:
          # Save the eval stack depth to restore to
          targetEvalStackDepth = wf.savedEvalStackDepth

          # Mark target as having returned with the return value
          debug("wfReturnValue: marking target activation as returned")
          targetActivation.hasReturned = true
          targetActivation.returnValue = returnVal

          # Preserve the target cleanup frame so it runs before caller work resumes.
          interp.pushWorkFrame(wf)
          preservedTargetCleanup = true

          # DON'T pop the target activation - let wfPopActivation handle it
          found = true
        else:
          # Pop intermediate activation (block)
          # Also mark it as returned so nested loops can detect the non-local return
          if interp.activationStack.len > 0:
            let intermediateAct = interp.activationStack[^1]
            intermediateAct.hasReturned = true
            intermediateAct.returnValue = returnVal
            debug("wfReturnValue: marked intermediate activation as returned, kind=", $intermediateAct.currentMethod.kind)
            discard interp.activationStack.pop()
            if interp.activationStack.len > 0:
              interp.currentActivation = interp.activationStack[^1]
              interp.currentReceiver = interp.currentActivation.receiver

    # If we haven't found the target yet, continue unwinding the activation stack
    # This handles the case where the target's wfPopActivation frame wasn't on the work queue
    if isNonLocalReturn and not found:
      while interp.activationStack.len > 0 and not found:
        let act = interp.activationStack[^1]
        if act == targetActivation:
          # Mark target as returned but DON'T pop it - let wfPopActivation handle that
          targetActivation.hasReturned = true
          targetActivation.returnValue = returnVal
          interp.currentActivation = targetActivation
          interp.currentReceiver = targetActivation.receiver
          found = true
        else:
          # Mark intermediate activation as returned
          act.hasReturned = true
          act.returnValue = returnVal
          discard interp.activationStack.pop()
          if interp.activationStack.len > 0:
            interp.currentActivation = interp.activationStack[^1]
            interp.currentReceiver = interp.currentActivation.receiver

    # Legacy executeMethod paths may not have target wfPopActivation on the queue.
    # Ensure target activation is marked returned so outer method handling can observe it.
    if isNonLocalReturn and not found and targetOnStack and targetActivation != nil:
      targetActivation.hasReturned = true
      targetActivation.returnValue = returnVal
      found = true
    
    # If we preserved the target cleanup frame, let that wfPopActivation push the
    # final value. Pushing it here would duplicate the return on the eval stack
    # and corrupt the caller's pending send/continuation state.
    if preservedTargetCleanup:
      return true

    # Note: We don't truncate the eval stack here because:
    # 1. If target wasn't found (escaped block), the caller handles cleanup
    # 2. Legacy executeMethod paths may still need the return value on-stack
    interp.pushValue(returnVal)
    return true

  of wfCascade:
    # Cascade - receiver is on stack, send each message to same receiver
    let receiverVal = interp.peekValue()  # Keep receiver on stack for next message
    let messages = frame.cascadeMessages

    if messages.len == 0:
      # No messages to send, just leave receiver on stack as result
      return true

    # Pop the receiver for processing (we'll push results back)
    discard interp.popValue()

    # Save original receiver and set cascade receiver
    let savedReceiver = interp.currentReceiver

    # Convert receiverVal to Instance
    var receiver: Instance
    case receiverVal.kind
    of vkInstance:
      receiver = receiverVal.instVal
    of vkInt:
      receiver = newIntInstance(integerClass, receiverVal.intVal)
    of vkFloat:
      receiver = newFloatInstance(floatClass, receiverVal.floatVal)
    of vkString:
      receiver = newStringInstance(stringClass, receiverVal.strVal)
    of vkArray:
      receiver = newArrayInstance(arrayClass, receiverVal.arrayVal)
    of vkTable:
      receiver = newTableInstance(tableClass, receiverVal.tableVal)
    of vkBool:
      let p = cast[pointer](new(bool))
      cast[ptr bool](p)[] = receiverVal.boolVal
      receiver = Instance(
        kind: ikObject,
        class: if receiverVal.boolVal: trueClassCache else: falseClassCache,
        slots: @[],
        isNimProxy: true,
        nimValue: p
      )
    of vkBlock:
      # Register BlockNode to keep it alive for ARC
      registerBlockNode(receiverVal.blockVal)
      receiver = Instance(
        kind: ikObject,
        class: blockClass,
        slots: @[],
        isNimProxy: false,
        nimValue: cast[pointer](receiverVal.blockVal)
      )
    of vkClass:
      receiver = Instance(
        kind: ikObject,
        class: objectClass,
        slots: @[],
        isNimProxy: false,
        nimValue: cast[pointer](receiverVal.classVal)
      )
    else:
      raise newException(ValueError, "Cascade to unsupported value kind: " & $receiverVal.kind)

    # Set current receiver for message sends
    interp.currentReceiver = receiver

    # For now, handle single message (push result) or loop for all messages
    # To properly handle multiple messages without recursion, we need to:
    # 1. Push frames for each message in reverse order
    # 2. Each message will leave its result on stack
    # 3. Only keep the last result

    if messages.len == 1:
      # Single message - just send it
      let msg = cast[MessageNode](messages[0])
      interp.pushWorkFrame(newAfterReceiverFrame(msg.selector, msg.arguments))
      interp.pushValue(receiverVal)  # Push receiver back for the message send
    else:
      # Multiple messages - push them in reverse order with cascade continuation
      # Push a final frame to restore receiver and keep only last result
      interp.pushWorkFrame(newRestoreReceiverFrame(savedReceiver))

      # Push all message frames in reverse order
      for i in countdown(messages.len - 1, 0):
        let msg = cast[MessageNode](messages[i])
        if i == messages.len - 1:
          # Last message - keep its result
          interp.pushWorkFrame(newCascadeMessageFrame(msg.selector, msg.arguments, receiverVal))
        else:
          # Intermediate message - discard result, keep receiver
          interp.pushWorkFrame(newCascadeMessageDiscardFrame(msg.selector, msg.arguments, receiverVal))

    return true

  of wfBuildArray:
    # Build array from N values on stack
    let count = frame.argCount
    var elements = newSeq[NodeValue](count)
    # Pop in reverse order to maintain original order
    for i in countdown(count - 1, 0):
      elements[i] = interp.popValue()
    if arrayClass != nil:
      interp.pushValue(newArrayInstance(arrayClass, elements).toValue())
    else:
      interp.pushValue(NodeValue(kind: vkArray, arrayVal: elements))
    return true

  of wfBuildTable:
    # Build table from key-value pairs on stack
    # Stack has: ... key1 value1 key2 value2 ... (in reverse order of pushing)
    # We need to pop values in pairs and build the table
    let pairCount = frame.argCount div 2
    var entries = initTable[NodeValue, NodeValue]()
    for i in 0..<pairCount:
      let value = interp.popValue()
      let key = interp.popValue()
      entries[key] = value
    if tableClass != nil:
      interp.pushValue(newTableInstance(tableClass, entries).toValue())
    else:
      interp.pushValue(NodeValue(kind: vkTable, tableVal: entries))
    return true

  of wfCascadeMessage, wfCascadeMessageDiscard:
    # Send a message in a cascade - receiver is stored in cascadeReceiver
    let receiverVal = frame.cascadeReceiver

    # Convert receiver to Instance
    var receiver: Instance
    case receiverVal.kind
    of vkInstance:
      receiver = receiverVal.instVal
    of vkInt:
      receiver = newIntInstance(integerClass, receiverVal.intVal)
    of vkFloat:
      receiver = newFloatInstance(floatClass, receiverVal.floatVal)
    of vkString:
      receiver = newStringInstance(stringClass, receiverVal.strVal)
    of vkArray:
      receiver = newArrayInstance(arrayClass, receiverVal.arrayVal)
    of vkTable:
      receiver = newTableInstance(tableClass, receiverVal.tableVal)
    of vkBool:
      let p = cast[pointer](new(bool))
      cast[ptr bool](p)[] = receiverVal.boolVal
      receiver = Instance(
        kind: ikObject,
        class: if receiverVal.boolVal: trueClassCache else: falseClassCache,
        slots: @[],
        isNimProxy: true,
        nimValue: p
      )
    of vkBlock:
      # Register BlockNode to keep it alive for ARC
      registerBlockNode(receiverVal.blockVal)
      receiver = Instance(
        kind: ikObject,
        class: blockClass,
        slots: @[],
        isNimProxy: false,
        nimValue: cast[pointer](receiverVal.blockVal)
      )
    of vkClass:
      receiver = Instance(
        kind: ikObject,
        class: objectClass,
        slots: @[],
        isNimProxy: false,
        nimValue: cast[pointer](receiverVal.classVal)
      )
    else:
      raise newException(ValueError, "Cascade to unsupported value kind: " & $receiverVal.kind)

    # Set current receiver
    interp.currentReceiver = receiver

    # Push receiver value for message send
    interp.pushValue(receiverVal)

    # Now handle arguments and send message
    if frame.pendingArgs.len == 0:
      interp.pushWorkFrame(newSendMessageFrame(frame.pendingSelector, 0))
    else:
      interp.pushWorkFrame(newAfterArgFrame(frame.pendingSelector, frame.pendingArgs, 0))
      interp.pushWorkFrame(newEvalFrame(frame.pendingArgs[0]))
    return true

  of wfRestoreReceiver:
    # Restore original receiver after cascade completes
    interp.currentReceiver = frame.savedReceiver
    return true

  of wfIfNodeContinuation:
    # IfNode specialization: condition result is on evalStack, execute appropriate branch
    # Blocks are already prepared with capturedEnv and homeActivation by the nkIf handler
    let condValue = interp.popValue()
    let condResult = condValue.isTruthy()
    if condResult and frame.thenBlock != nil:
      interp.pushWorkFrame(newApplyBlockFrame(frame.thenBlock, 0))
    elif not condResult and frame.elseBlock != nil:
      interp.pushWorkFrame(newApplyBlockFrame(frame.elseBlock, 0))
    else:
      interp.pushValue(nilValue())
    return true

  of wfIfBranch:
    # Handle conditional branch (ifTrue: or ifFalse:)
    if frame.conditionResult:
      # Condition is true - execute then block
      interp.pushWorkFrame(newApplyBlockFrame(frame.thenBlock, 0))
    elif frame.elseBlock != nil:
      # Condition is false - execute else block
      interp.pushWorkFrame(newApplyBlockFrame(frame.elseBlock, 0))
    else:
      # No else block - return nil
      interp.pushValue(nilValue())
    return true

  of wfWhileLoop:
    # Handle while loop (whileTrue: or whileFalse:)
    # Reuses the current frame by mutating loopState and re-pushing
    case frame.loopState
    of lsEvaluateCondition:
      # Reuse frame for next state
      frame.loopState = lsCheckCondition
      frame.skipRelease = true
      interp.pushWorkFrame(frame)
      frame.conditionBlock.homeActivation = interp.currentActivation
      if interp.currentActivation != nil:
        interp.currentActivation.wasCaptured = true
      interp.pushWorkFrame(newApplyBlockFrame(frame.conditionBlock, 0))
      return true
    of lsCheckCondition:
      # Check the condition result on the stack
      let conditionResult = interp.peekValue()
      let condBool = conditionResult.isTruthy()
      let shouldContinue = if frame.loopKind: condBool else: not condBool
      discard interp.popValue()  # Clean up condition result
      if shouldContinue:
        # Continue loop - reuse frame for body execution
        frame.loopState = lsExecuteBody
        frame.skipRelease = true
        interp.pushWorkFrame(frame)
        # Update body block home activation for this invocation
        if interp.currentActivation != nil and not interp.currentActivation.hasReturned:
          frame.bodyBlock.homeActivation = interp.currentActivation
          interp.currentActivation.wasCaptured = true
        interp.pushWorkFrame(newApplyBlockFrame(frame.bodyBlock, 0))
      else:
        # Loop done - push nil result
        interp.pushValue(nilValue())
      return true
    of lsExecuteBody:
      # Transition to lsLoopBody state - reuse frame
      frame.loopState = lsLoopBody
      frame.skipRelease = true
      interp.pushWorkFrame(frame)
      return true
    of lsLoopBody:
      # Body completed - discard body result and loop back to condition
      discard interp.popValue()

      # Loop back - reuse frame
      frame.loopState = lsEvaluateCondition
      frame.skipRelease = true
      interp.pushWorkFrame(frame)
      return true
    of lsDone:
      return true

  of wfPushHandler:
    # Push exception handler onto handler stack
    # Use the saved work queue depth from before any handler frames were pushed
    debug("wfPushHandler: activationStack.len=", interp.activationStack.len, " workQueue.len=", interp.workQueue.len)
    if interp.currentActivation != nil:
      interp.currentActivation.wasCaptured = true
    let handler = ExceptionHandler(
      exceptionClass: frame.exceptionClass,
      handlerBlock: frame.handlerBlock,
      activation: interp.currentActivation,
      stackDepth: interp.activationStack.len,
      workQueueDepth: frame.savedWorkQueueDepth,  # Depth before handler frames were pushed
      evalStackDepth: interp.evalStack.len,
      protectedBlock: frame.protectedBlockForHandler
    )
    interp.exceptionHandlers.add(handler)
    debug("VM: wfPushHandler pushed handler for ", frame.exceptionClass.name)
    return true

  of wfPopHandler:
    # Pop exception handler from handler stack
    # If no exception occurred, the topmost handler is ours.
    # If an exception WAS caught, the handler was already removed by signal,
    # and this wfPopHandler was removed from WQ by truncation.
    if interp.exceptionHandlers.len > 0:
      let popped = interp.exceptionHandlers.pop()
      if popped != nil and popped.exceptionContext != nil:
        unregisterExceptionContext(popped.exceptionContext)
    return true

  of wfExceptionReturn:
    # Handler block completed (fell through without calling return:/pass/retry)
    # Pop the handler result and use it as on:do:'s return value
    let handlerIdx = frame.handlerIndex
    if handlerIdx < interp.exceptionHandlers.len:
      # Remove handler
      interp.truncateExceptionHandlers(handlerIdx)
    # Handler block's result is already on evalStack from wfApplyBlock
    # It becomes the on:do: return value - nothing more to do
    return true

  of wfSignalException:
    # Signal exception - this is handled by primitiveSignalImpl
    # which schedules the handler block directly
    # This case should not normally be reached
    debug("VM: wfSignalException - should be handled by primitiveSignalImpl")
    return true

  of wfEvalNode:
    # Should not reach here - wfEvalNode is handled in handleEvalNode
    return handleEvalNode(interp, frame)

# Main execution loop
proc runASTInterpreter*(interp: var Interpreter): VMResult =
  ## Main execution loop for the explicit stack AST interpreter
  ## Returns when:
  ## - Work queue is empty (vmCompleted)
  ## - Processor yields (vmYielded)
  ## - Error occurs (vmError)

  {.computedGoto.}  # Optimize case statement dispatch
  while interp.hasWorkFrames():
    # Check for yield
    if interp.shouldYield:
      interp.shouldYield = false
      return VMResult(status: vmYielded, value: interp.peekValue())

    while interp.currentActivation != nil and interp.currentActivation.hasReturned and
          interp.workQueue.len > 0 and interp.workQueue[^1].kind != wfPopActivation:
      let staleFrame = interp.popWorkFrame()
      releaseFrame(staleFrame)

    let frame = interp.popWorkFrame()
    debug("VM: Processing frame kind=", frame.kind)

    when defined(debugger):
      # Check debugger hook for breakpoints and stepping
      checkDebuggerHook(interp, frame)

    try:
      let shouldContinue = case frame.kind
        of wfEvalNode:
          handleEvalNode(interp, frame)
        else:
          handleContinuation(interp, frame)

      # Release frame back to pool (unless it was re-pushed onto the queue)
      if frame.skipRelease:
        frame.skipRelease = false
      else:
        releaseFrame(frame)

      if not shouldContinue:
        break
    except ResumeException:
      # Resume was called - work queue and eval stack already restored
      # Just continue processing the restored work queue
      if not frame.skipRelease:
        releaseFrame(frame)
      frame.skipRelease = false
      debug("VM: ResumeException caught, continuing with restored work queue")
    except DivByZeroDefect as e:
      if not frame.skipRelease:
        releaseFrame(frame)
      frame.skipRelease = false
      # Convert Nim DivByZeroDefect to Harding DivisionByZero exception
      signalExceptionByName(interp, "DivisionByZero", e.msg)
      # Continue processing - signalExceptionByName schedules the handler
      continue
    except ValueError as e:
      if not frame.skipRelease:
        releaseFrame(frame)
      return VMResult(status: vmError, error: e.msg)
    except Exception as e:
      if not frame.skipRelease:
        releaseFrame(frame)
      return VMResult(status: vmError, error: "VM error: " & e.msg)

  # Execution complete
  let resultValue = if interp.evalStack.len > 0:
                      interp.evalStack[^1]
                    else:
                      nilValue()
  
  debug("VM completed: evalStack.len=", interp.evalStack.len, " resultValue.kind=", resultValue.kind)
  if resultValue.kind == vkInstance:
    debug("VM completed: result is Instance, instVal.kind=", resultValue.instVal.kind)

  return VMResult(status: vmCompleted, value: resultValue)

# Entry point to evaluate an expression using the new VM
proc evalWithVM*(interp: var Interpreter, node: Node): NodeValue =
  ## Evaluate an expression using the explicit stack VM
  ## Handles re-entrancy by saving/restoring VM state for nested calls
  if node == nil:
    return nilValue()

  # Save current VM state for re-entrancy support
  let savedWorkQueue = interp.workQueue
  let savedEvalStack = interp.evalStack

  # Initialize fresh VM state for this evaluation
  interp.workQueue = newSeqOfCap[WorkFrame](64)
  interp.workQueue.add(newEvalFrame(node))
  interp.evalStack = newSeqOfCap[NodeValue](32)

  # Run the VM
  let vmResult = interp.runASTInterpreter()

  # Get result before restoring state
  let resultValue = case vmResult.status
    of vmCompleted, vmYielded:
      vmResult.value
    of vmError:
      raise newException(ValueError, vmResult.error)
    of vmRunning:
      nilValue()

  # Restore previous VM state
  interp.workQueue = savedWorkQueue
  interp.evalStack = savedEvalStack

  return resultValue

proc evalWithVMCleanContext*(interp: var Interpreter, node: Node): NodeValue =
  ## Evaluate an expression with a clean activation context.
  ## This saves and clears the activation stack before evaluation,
  ## then restores it afterwards. Use this for external callbacks
  ## (like GTK signals) that need isolated block execution.
  if node == nil:
    return nilValue()

  # Save activation context
  let savedActivationStack = interp.activationStack
  let savedCurrentActivation = interp.currentActivation
  let savedCurrentReceiver = interp.currentReceiver

  # Clear activation context for clean evaluation
  interp.activationStack = @[]
  interp.currentActivation = nil
  interp.currentReceiver = nil

  # Evaluate with clean context and always restore on error
  try:
    let evalResult = interp.evalWithVM(node)
    interp.activationStack = savedActivationStack
    interp.currentActivation = savedCurrentActivation
    interp.currentReceiver = savedCurrentReceiver
    return evalResult
  except Exception:
    interp.activationStack = savedActivationStack
    interp.currentActivation = savedCurrentActivation
    interp.currentReceiver = savedCurrentReceiver
    raise

proc doit*(interp: var Interpreter, source: string, dumpAst = false): (NodeValue, string) =
  ## Parse and evaluate source code using the stackless VM
  let tokens = lex(source)
  var parser = initParser(tokens)
  let nodes = parser.parseStatements()

  if parser.hasError:
    return (nilValue(), "Parse error: " & parser.errorMsg)

  if nodes.len == 0:
    return (nilValue(), "No expression to evaluate")

  # Dump AST if requested
  if dumpAst:
    echo "AST:"
    for node in nodes:
      echo printAST(node)

  # Evaluate all nodes using stackless VM with clean context, return last result
  try:
    var lastResult = nilValue()
    for node in nodes:
      lastResult = interp.evalWithVMCleanContext(node)
    interp.lastResult = lastResult
    return (lastResult, "")
  except ValueError:
    raise
  except EvalError as e:
    return (nilValue(), "Runtime error: " & e.msg)
  except Exception as e:
    return (nilValue(), "Error: " & e.msg)

proc evalStatements*(interp: var Interpreter, source: string): (seq[NodeValue], string) =
  ## Parse and evaluate multiple statements using the stackless VM
  ## 
  ## Smalltalk-style: Compiles source as #doIt method on UndefinedObject (nil)
  ## This ensures non-local returns (^) have a proper method activation to return from,
  ## just like in Smalltalk workspaces where code is compiled as #doIt method.
  ##
  ## Usage: evalStatements(source) -> executes as "nil doIt" where doIt contains the source
  let tokens = lex(source)
  var parser = initParser(tokens)
  let nodes = parser.parseStatements()

  if parser.hasError:
    return (@[], "Parse error: " & parser.errorMsg)

  if nodes.len == 0:
    return (@[], "")

  # Create the #doIt method on UndefinedObject with source as its body
  # This is the Smalltalk convention: top-level code is compiled as #doIt
  let doItMethod = BlockNode(
    parameters: @[],
    temporaries: @[],
    body: nodes,
    isMethod: true,  # It's a real method
    capturedEnv: initTable[string, MutableCell](),
    capturedEnvInitialized: true,
    selector: "doIt"
  )
  
  # Add the method to UndefinedObject's method table
  undefinedObjectClass.methods["doIt"] = doItMethod
  undefinedObjectClass.allMethods["doIt"] = doItMethod
  
  # Execute: nil doIt
  # This creates a proper method activation that blocks can return from
  var results = newSeq[NodeValue]()
  try:
    let methodResult = executeMethod(interp, doItMethod, nilInstance, @[], undefinedObjectClass)
    results.add(methodResult)
  except ValueError as e:
    return (@[], "Error: " & e.msg)
  except EvalError as e:
    return (@[], "Runtime error: " & e.msg)
  except Exception as e:
    return (@[], "Error: " & e.msg & "\n" & e.getStackTrace())
  finally:
    # Clean up: remove the temporary doIt method
    undefinedObjectClass.methods.del("doIt")
    undefinedObjectClass.allMethods.del("doIt")

  return (results, "")

proc evalScriptBlock*(interp: var Interpreter, source: string): (NodeValue, string) =
  ## Evaluate source as a block with self = nil (Smalltalk workspace convention)
  ## Source should be wrapped in [ ... ] by the caller
  ## This allows temporary variable declarations like | counter total |
  let tokens = lex(source)
  var parser = initParser(tokens)
  let nodes = parser.parseStatements()

  if parser.hasError:
    return (nilValue(), "Parse error: " & parser.errorMsg)

  if nodes.len == 0:
    return (nilValue(), "No expression to evaluate")

  # We expect a single block node
  var blockNode: BlockNode
  if nodes.len == 1 and nodes[0].kind == nkBlock:
    blockNode = nodes[0].BlockNode
  else:
    return (nilValue(), "Expected a single block expression")

  try:
    let savedReceiver = interp.currentReceiver
    interp.currentReceiver = nilInstance

    let blockResult = interp.invokeBlock(blockNode, @[])

    interp.currentReceiver = savedReceiver

    return (blockResult, "")
  except EvalError as e:
    return (nilValue(), "Runtime error: " & e.msg)
  except Exception as e:
    return (nilValue(), "Error: " & e.msg)

proc evalForProcess*(interp: var Interpreter, node: Node): (NodeValue, VMStatus) =
  ## Evaluate a node for a process, preserving VM state across yields.
  ## This is used by the scheduler to execute one statement at a time,
  ## allowing proper yield/resume semantics.
  ##
  ## If node is nil and work queue has pending frames, continues from work queue.
  ## If node is not nil and work queue is empty, pushes node onto work queue.
  ##
  ## Returns (value, status) where status indicates if the VM yielded,
  ## completed, or encountered an error.
  if node == nil and interp.workQueue.len == 0:
    return (nilValue(), vmCompleted)

  # If work queue is empty, push the new node
  if interp.workQueue.len == 0:
    interp.workQueue.add(newEvalFrame(node))
  # If work queue has pending work (resuming from yield), continue execution
  # without pushing a new frame

  # Run the VM (continues from where it left off if resuming)
  let vmResult = interp.runASTInterpreter()

  return (vmResult.value, vmResult.status)
